// game.ts: Управляет отрисовкой игрового мира в "Сочном" векторном стиле.
import { Player, Players, WorldMap, TileType } from './types';

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;

export const TILE_SIZE = 40;
let world: WorldMap = {};

// --- ПАЛИТРА ---
const COLORS = {
    grassLight: '#A3E635', // Lime-400
    grassDark: '#65A30D',  // Lime-600 (для деталей)
    water: '#22D3EE',      // Cyan-400
    waterFoam: '#E0F2FE',  // Sky-100
    stoneBase: '#94A3B8',  // Slate-400
    stoneDark: '#475569',  // Slate-600
    stoneHighlight: '#E2E8F0', // Slate-200
    treeTrunk: '#78350F',  // Amber-900
    treeLeafLight: '#4ADE80', // Green-400
    treeLeafDark: '#166534',  // Green-800
    shadow: 'rgba(0, 0, 0, 0.2)'
};

/**
 * Инициализирует игровой холст и генерирует начальную область мира.
 */
export function init(canvasElement: HTMLCanvasElement, player: Player) {
  canvas = canvasElement;
  ctx = canvas.getContext('2d');
  // Улучшаем четкость на Retina экранах
  const dpr = window.devicePixelRatio || 1;
  // Обратите внимание: размеры canvas в DOM должны быть установлены через CSS или атрибуты,
  // здесь мы полагаемся на то, что они уже заданы в index.html

  generateWorld(player.x, player.y);
}

/**
 * Генерирует мир.
 */
function generateWorld(playerX: number, playerY: number) {
    world = {}; 
    const playerTileX = Math.floor(playerX / TILE_SIZE);
    const playerTileY = Math.floor(playerY / TILE_SIZE);

    const WORLD_RADIUS = 60; 
    for (let x = playerTileX - WORLD_RADIUS; x < playerTileX + WORLD_RADIUS; x++) {
        for (let y = playerTileY - WORLD_RADIUS; y < playerTileY + WORLD_RADIUS; y++) {
            const key = `${x},${y}`;
            const dist = Math.sqrt(Math.pow(playerTileX - x, 2) + Math.pow(playerTileY - y, 2));

            if (dist < 4) {
                world[key] = 'grass';
                continue;
            }

            // Простой шум для генерации
            const noise = Math.sin(x * 0.5) * Math.cos(y * 0.5);
            const rand = Math.random();

            if (noise > 0.8) {
                world[key] = 'water';
            } else if (rand < 0.12) {
                world[key] = 'tree';
            } else if (rand < 0.15) {
                world[key] = 'stone';
            } else {
                world[key] = 'grass';
            }
        }
    }
}

export function getTile(tileX: number, tileY: number): TileType {
    return world[`${Math.floor(tileX)},${Math.floor(tileY)}`] || 'grass';
}

export function destroyTile(tileX: number, tileY: number) {
    world[`${tileX},${tileY}`] = 'grass';
}

export function canMoveTo(x: number, y: number, width: number, height: number): boolean {
    // Уменьшаем хитбокс для более приятного перемещения ("скольжение" по углам)
    const padding = 10; 
    const checkWidth = width - padding;
    const checkHeight = height - padding;

    const corners = [
        { x: x - checkWidth / 2, y: y - checkHeight / 2 + 5 }, // Смещаем хитбокс к ногам
        { x: x + checkWidth / 2, y: y - checkHeight / 2 + 5 },
        { x: x - checkWidth / 2, y: y + checkHeight / 2 }, 
        { x: x + checkWidth / 2, y: y + checkHeight / 2 }, 
    ];

    for (const corner of corners) {
        const tileX = Math.floor(corner.x / TILE_SIZE);
        const tileY = Math.floor(corner.y / TILE_SIZE);
        const tileType = getTile(tileX, tileY);
        if (tileType === 'tree' || tileType === 'stone' || tileType === 'water') {
            return false;
        }
    }
    return true;
}

// --- ФУНКЦИИ ОТРИСОВКИ ---

/**
 * Детерминированный генератор случайных чисел для визуальных эффектов (травинки, цветы).
 * Позволяет тайлу выглядеть одинаково в каждом кадре без хранения состояния.
 */
function pseudoRandom(x: number, y: number) {
    return Math.abs(Math.sin(x * 12.9898 + y * 78.233) * 43758.5453) % 1;
}

function drawShadow(ctx: CanvasRenderingContext2D, x: number, y: number, width: number) {
    ctx.fillStyle = COLORS.shadow;
    ctx.beginPath();
    // Рисуем сплюснутый овал под объектом
    ctx.ellipse(x, y, width / 2, width / 4, 0, 0, Math.PI * 2);
    ctx.fill();
}

function drawGrass(ctx: CanvasRenderingContext2D, x: number, y: number, worldX: number, worldY: number) {
    ctx.fillStyle = COLORS.grassLight;
    // Рисуем базу чуть больше тайла, чтобы перекрыть швы
    ctx.fillRect(x - 0.5, y - 0.5, TILE_SIZE + 1, TILE_SIZE + 1);

    // Процедурные детали (травинки/пятна)
    const rand = pseudoRandom(worldX, worldY);
    if (rand > 0.7) {
        ctx.fillStyle = COLORS.grassDark;
        ctx.globalAlpha = 0.2;
        ctx.beginPath();
        ctx.arc(x + TILE_SIZE * 0.5, y + TILE_SIZE * 0.5, 4, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 1.0;
    }
    if (rand < 0.1) {
        // Цветочек
        ctx.fillStyle = '#F472B6'; // Pink
        ctx.beginPath();
        ctx.arc(x + TILE_SIZE * 0.7, y + TILE_SIZE * 0.3, 3, 0, Math.PI * 2);
        ctx.fill();
    }
}

function drawWater(ctx: CanvasRenderingContext2D, x: number, y: number) {
    ctx.fillStyle = COLORS.water;
    ctx.fillRect(x - 0.5, y - 0.5, TILE_SIZE + 1, TILE_SIZE + 1);

    // Блик/Пена сверху
    ctx.fillStyle = COLORS.waterFoam;
    ctx.globalAlpha = 0.5;
    ctx.beginPath();
    ctx.roundRect(x + 5, y + 5, TILE_SIZE - 10, 5, 5);
    ctx.fill();
    ctx.globalAlpha = 1.0;
}

function drawTree(ctx: CanvasRenderingContext2D, x: number, y: number) {
    // Центр тайла
    const cx = x + TILE_SIZE / 2;
    const cy = y + TILE_SIZE / 2;

    // Тень
    drawShadow(ctx, cx, cy + 15, 26);

    // Ствол
    ctx.fillStyle = COLORS.treeTrunk;
    const trunkWidth = 12;
    const trunkHeight = 20;
    ctx.beginPath();
    ctx.roundRect(cx - trunkWidth / 2, cy - 5, trunkWidth, trunkHeight, 4);
    ctx.fill();

    // Крона (3 круга для "пушистости")
    ctx.fillStyle = COLORS.treeLeafLight;
    ctx.strokeStyle = COLORS.treeLeafDark;
    ctx.lineWidth = 3;

    const drawLeafCluster = (lx: number, ly: number, r: number) => {
        ctx.beginPath();
        ctx.arc(lx, ly, r, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    };

    // Рисуем крону со смещением вверх для 3D эффекта
    drawLeafCluster(cx - 10, cy - 20, 14);
    drawLeafCluster(cx + 10, cy - 20, 14);
    drawLeafCluster(cx, cy - 30, 16);
}

function drawStone(ctx: CanvasRenderingContext2D, x: number, y: number) {
    const cx = x + TILE_SIZE / 2;
    const cy = y + TILE_SIZE / 2;

    drawShadow(ctx, cx, cy + 12, 30);

    // Камень (смещение вверх)
    const stoneY = cy - 5;

    // Основная форма
    ctx.fillStyle = COLORS.stoneBase;
    ctx.strokeStyle = COLORS.stoneDark;
    ctx.lineWidth = 3;

    ctx.beginPath();
    // Рисуем валун как скругленный прямоугольник/эллипс
    ctx.roundRect(cx - 14, stoneY - 12, 28, 24, 10);
    ctx.fill();
    ctx.stroke();

    // Блик
    ctx.fillStyle = COLORS.stoneHighlight;
    ctx.beginPath();
    ctx.ellipse(cx - 6, stoneY - 6, 4, 2, Math.PI / 4, 0, Math.PI * 2);
    ctx.fill();
}

function drawPlayer(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean) {
    // Тень
    drawShadow(ctx, player.x, player.y + 18, 30);

    // Руки (анимируем немного если игрок двигается, но здесь просто статично для стиля)
    const time = Date.now() / 200;
    const handOffset = Math.sin(time) * 2;

    ctx.fillStyle = player.color;
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 2;

    // Левая рука
    ctx.beginPath();
    ctx.arc(player.x - 18, player.y + 5 + handOffset, 6, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();

    // Правая рука
    ctx.beginPath();
    ctx.arc(player.x + 18, player.y + 5 - handOffset, 6, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();

    // Тело
    ctx.beginPath();
    ctx.arc(player.x, player.y, 18, 0, Math.PI * 2);
    ctx.fillStyle = player.color;
    ctx.fill();

    // Обводка тела (Золотая для себя, Белая для других)
    ctx.strokeStyle = isLocal ? '#FCD34D' : '#FFFFFF'; // Amber-300 or White
    ctx.lineWidth = 4;
    ctx.stroke();

    // "Блик" на голове для объема
    ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
    ctx.beginPath();
    ctx.arc(player.x, player.y - 8, 10, 0, Math.PI * 2);
    ctx.fill();

    // Никнейм
    ctx.fillStyle = 'white';
    ctx.font = 'bold 14px "Segoe UI", Roboto, Helvetica, Arial, sans-serif';
    ctx.textAlign = 'center';

    // Тень текста
    ctx.shadowColor = 'rgba(0,0,0,0.8)';
    ctx.shadowBlur = 4;
    ctx.fillText(player.nickname, player.x, player.y - 28);
    ctx.shadowBlur = 0; // Сброс
}

interface RenderObject {
    y: number; // Для сортировки по глубине (Z-index)
    type: 'tree' | 'stone' | 'player';
    data: any; // Координаты или объект игрока
}

/**
 * Отрисовывает все игровые объекты на холсте с учетом псевдо-объема и сортировки.
 */
export function renderGame(players: Players, myId: string) {
  if (!ctx || !canvas) return;
  const me = players[myId];
  if (!me) return;

  const cameraX = me.x - canvas.width / 2;
  const cameraY = me.y - canvas.height / 2;

  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.save();
  ctx.translate(-cameraX, -cameraY);

  const startTileX = Math.floor(cameraX / TILE_SIZE) - 1;
  const endTileX = startTileX + Math.ceil(canvas.width / TILE_SIZE) + 2;
  const startTileY = Math.floor(cameraY / TILE_SIZE) - 1;
  const endTileY = startTileY + Math.ceil(canvas.height / TILE_SIZE) + 2;

  const renderList: RenderObject[] = [];

  // 1. Проход: Рисуем пол (Трава, Вода) - они всегда снизу.
  // И собираем объекты (Деревья, Камни) в список для сортировки.
  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const type = getTile(x, y);
        const screenX = x * TILE_SIZE;
        const screenY = y * TILE_SIZE;

        if (type === 'water') {
            drawWater(ctx, screenX, screenY);
        } else {
            // Рисуем траву под деревьями и камнями тоже, чтобы не было дырок
            drawGrass(ctx, screenX, screenY, x, y);
        }

        if (type === 'tree') {
            // Добавляем в список рендера. Y - это "низ" объекта
            renderList.push({ y: screenY + TILE_SIZE, type: 'tree', data: { x: screenX, y: screenY } });
        } else if (type === 'stone') {
            renderList.push({ y: screenY + TILE_SIZE, type: 'stone', data: { x: screenX, y: screenY } });
        }
    }
  }

  // 2. Добавляем игроков в список рендера
  for (const id in players) {
      const p = players[id];
      // Y игрока - это его координата Y (центр или ноги). 
      // Так как мы рисуем игрока с центром в x,y, используем y + radius как точку опоры
      renderList.push({ y: p.y + 10, type: 'player', data: { player: p, isLocal: id === myId } });
  }

  // 3. Сортируем все объекты по Y (Painter's Algorithm)
  renderList.sort((a, b) => a.y - b.y);

  // 4. Рисуем отсортированные объекты
  for (const obj of renderList) {
      if (obj.type === 'tree') {
          drawTree(ctx, obj.data.x, obj.data.y);
      } else if (obj.type === 'stone') {
          drawStone(ctx, obj.data.x, obj.data.y);
      } else if (obj.type === 'player') {
          drawPlayer(ctx, obj.data.player, obj.data.isLocal);
      }
  }

  ctx.restore();
}

// game.ts: Управляет отрисовкой игрового мира в стиле Retro Pixel RPG (Gritty).
import { Player, Players, WorldMap, TileType } from './types';

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;

export const TILE_SIZE = 40;
let world: WorldMap = {};

// Кэш сгенерированных текстур
const textures: Record<string, HTMLCanvasElement> = {};

// --- ГЕНЕРАЦИЯ ТЕКСТУР (PIXEL ART) ---

/**
 * Создает canvas с нарисованным на нем пиксельным шумом.
 */
function createNoiseCanvas(width: number, height: number, baseColor: string, noiseColors: string[], density: number): HTMLCanvasElement {
    const c = document.createElement('canvas');
    c.width = width;
    c.height = height;
    const cx = c.getContext('2d')!;

    // Базовый цвет
    cx.fillStyle = baseColor;
    cx.fillRect(0, 0, width, height);

    // Рисуем шум "пикселями" 2x2 для ретро эффекта
    const pixelSize = 2;
    for (let i = 0; i < (width * height * density) / (pixelSize * pixelSize); i++) {
        const x = Math.floor(Math.random() * (width / pixelSize)) * pixelSize;
        const y = Math.floor(Math.random() * (height / pixelSize)) * pixelSize;
        cx.fillStyle = noiseColors[Math.floor(Math.random() * noiseColors.length)];
        cx.fillRect(x, y, pixelSize, pixelSize);
    }
    return c;
}

function generateTextures() {
    // 1. Трава (Грязная, болотная)
    textures['grass'] = createNoiseCanvas(TILE_SIZE, TILE_SIZE, '#2d3a25', ['#3a4d31', '#1f2919', '#4a3c2a'], 0.6);

    // 2. Вода (Темная, глубокая)
    textures['water'] = createNoiseCanvas(TILE_SIZE, TILE_SIZE, '#1e3a52', ['#264d6e', '#152838', '#386c91'], 0.5);

    // 3. Камень (Спрайт валуна)
    const stoneC = document.createElement('canvas');
    stoneC.width = TILE_SIZE;
    stoneC.height = TILE_SIZE;
    const sCtx = stoneC.getContext('2d')!;

    // Тень
    sCtx.fillStyle = 'rgba(0,0,0,0.4)';
    sCtx.fillRect(5, TILE_SIZE - 8, TILE_SIZE - 10, 6);

    // Форма камня (грубая)
    sCtx.fillStyle = '#555555';
    sCtx.fillRect(4, 10, TILE_SIZE - 8, TILE_SIZE - 14);

    // Шум на камне
    const pixelSize = 2;
    for (let i = 0; i < 40; i++) {
        const x = 4 + Math.floor(Math.random() * (TILE_SIZE - 12));
        const y = 10 + Math.floor(Math.random() * (TILE_SIZE - 18));
        sCtx.fillStyle = Math.random() > 0.5 ? '#333' : '#777';
        sCtx.fillRect(x, y, pixelSize, pixelSize);
    }

    // Трещины
    sCtx.fillStyle = '#222';
    sCtx.fillRect(10, 15, 6, 2);
    sCtx.fillRect(14, 17, 2, 4);

    textures['stone'] = stoneC;

    // 4. Дерево (Сосна)
    const treeC = document.createElement('canvas');
    treeC.width = TILE_SIZE;
    treeC.height = TILE_SIZE + 20; // Выше чем тайл
    const tCtx = treeC.getContext('2d')!;

    // Тень
    tCtx.fillStyle = 'rgba(0,0,0,0.4)';
    tCtx.fillRect(10, TILE_SIZE - 5, 20, 6);

    // Ствол
    tCtx.fillStyle = '#3e2723'; // Dark brown
    tCtx.fillRect(16, TILE_SIZE - 10, 8, 12);

    // Листва (Пиксельная пирамида)
    const drawLeafLayer = (y: number, w: number) => {
        tCtx.fillStyle = '#1b3318'; // Dark green base
        const startX = (TILE_SIZE - w) / 2;
        tCtx.fillRect(startX, y, w, 12);

        // Шум листвы
        for(let i=0; i<15; i++) {
            const lx = startX + Math.random() * w;
            const ly = y + Math.random() * 12;
            tCtx.fillStyle = Math.random() > 0.5 ? '#284524' : '#0f1f0d';
            tCtx.fillRect(Math.floor(lx/2)*2, Math.floor(ly/2)*2, 2, 2);
        }
    };

    drawLeafLayer(TILE_SIZE - 20, 28);
    drawLeafLayer(TILE_SIZE - 30, 22);
    drawLeafLayer(TILE_SIZE - 40, 14);

    textures['tree'] = treeC;
}


/**
 * Инициализирует игровой холст и генерирует начальную область мира.
 */
export function init(canvasElement: HTMLCanvasElement, player: Player) {
  canvas = canvasElement;
  ctx = canvas.getContext('2d');

  // Отключаем сглаживание для Pixel Art стиля
  if (ctx) {
      ctx.imageSmoothingEnabled = false;
  }

  generateTextures();
  generateWorld(player.x, player.y);
}

/**
 * Генерирует мир.
 */
function generateWorld(playerX: number, playerY: number) {
    world = {}; 
    const playerTileX = Math.floor(playerX / TILE_SIZE);
    const playerTileY = Math.floor(playerY / TILE_SIZE);

    const WORLD_RADIUS = 60; 
    for (let x = playerTileX - WORLD_RADIUS; x < playerTileX + WORLD_RADIUS; x++) {
        for (let y = playerTileY - WORLD_RADIUS; y < playerTileY + WORLD_RADIUS; y++) {
            const key = `${x},${y}`;
            const dist = Math.sqrt(Math.pow(playerTileX - x, 2) + Math.pow(playerTileY - y, 2));

            if (dist < 4) {
                world[key] = 'grass';
                continue;
            }

            const noise = Math.sin(x * 0.4) * Math.cos(y * 0.4); // Более плавный шум
            const rand = Math.random();

            if (noise > 0.75) {
                world[key] = 'water';
            } else if (rand < 0.10) {
                world[key] = 'tree';
            } else if (rand < 0.12) {
                world[key] = 'stone';
            } else {
                world[key] = 'grass';
            }
        }
    }
}

export function getTile(tileX: number, tileY: number): TileType {
    return world[`${Math.floor(tileX)},${Math.floor(tileY)}`] || 'grass';
}

export function destroyTile(tileX: number, tileY: number) {
    world[`${tileX},${tileY}`] = 'grass';
}

export function canMoveTo(x: number, y: number, width: number, height: number): boolean {
    const padding = 12; 
    const checkWidth = width - padding;
    const checkHeight = height - padding;

    const corners = [
        { x: x - checkWidth / 2, y: y - checkHeight / 2 + 5 },
        { x: x + checkWidth / 2, y: y - checkHeight / 2 + 5 },
        { x: x - checkWidth / 2, y: y + checkHeight / 2 }, 
        { x: x + checkWidth / 2, y: y + checkHeight / 2 }, 
    ];

    for (const corner of corners) {
        const tileX = Math.floor(corner.x / TILE_SIZE);
        const tileY = Math.floor(corner.y / TILE_SIZE);
        const tileType = getTile(tileX, tileY);
        if (tileType === 'tree' || tileType === 'stone' || tileType === 'water') {
            return false;
        }
    }
    return true;
}

// --- ОТРИСОВКА ---

function drawPlayerPixel(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean) {
    const px = player.x;
    const py = player.y;

    // Тень
    ctx.fillStyle = 'rgba(0,0,0,0.5)';
    ctx.fillRect(px - 10, py + 12, 20, 6);

    // Используем цвет игрока для "Одежды"
    ctx.fillStyle = player.color;
    // Корпус (Квадратный, Retro style)
    ctx.fillRect(px - 10, py - 10, 20, 24);

    // Добавляем шум ткани
    ctx.fillStyle = 'rgba(0,0,0,0.2)';
    for(let i=0; i<10; i++) {
        ctx.fillRect(px - 10 + Math.random()*20, py - 10 + Math.random()*24, 2, 2);
    }

    // Голова (Телесный цвет)
    ctx.fillStyle = '#e0ac69';
    ctx.fillRect(px - 6, py - 20, 12, 12);

    // Волосы (Темные)
    ctx.fillStyle = '#3e2723';
    ctx.fillRect(px - 6, py - 20, 12, 4);
    ctx.fillRect(px - 8, py - 18, 2, 6);
    ctx.fillRect(px + 6, py - 18, 2, 6);

    // Глаза
    ctx.fillStyle = '#000';
    ctx.fillRect(px - 4, py - 14, 2, 2);
    ctx.fillRect(px + 2, py - 14, 2, 2);

    // Обводка (если локальный игрок)
    if (isLocal) {
        ctx.strokeStyle = '#ffd700'; // Gold
        ctx.lineWidth = 2;
        ctx.strokeRect(px - 11, py - 21, 22, 36);
    } else {
        // Никнейм только для других
        ctx.fillStyle = '#ddd';
        ctx.font = '10px monospace';
        ctx.textAlign = 'center';
        ctx.fillText(player.nickname, px, py - 26);
    }
}

interface RenderObject {
    y: number; // Z-index
    type: 'tree' | 'stone' | 'player';
    data: any;
}

export function renderGame(players: Players, myId: string) {
  if (!ctx || !canvas) return;
  const me = players[myId];
  if (!me) return;

  // Pixel Art требует жестких пикселей
  ctx.imageSmoothingEnabled = false;

  const cameraX = Math.floor(me.x - canvas.width / 2);
  const cameraY = Math.floor(me.y - canvas.height / 2);

  ctx.fillStyle = '#111'; // Черный фон за пределами карты
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  ctx.save();
  ctx.translate(-cameraX, -cameraY);

  const startTileX = Math.floor(cameraX / TILE_SIZE) - 1;
  const endTileX = startTileX + Math.ceil(canvas.width / TILE_SIZE) + 2;
  const startTileY = Math.floor(cameraY / TILE_SIZE) - 1;
  const endTileY = startTileY + Math.ceil(canvas.height / TILE_SIZE) + 2;

  const renderList: RenderObject[] = [];

  // 1. Рисуем пол (Трава, Вода)
  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const type = getTile(x, y);
        const screenX = x * TILE_SIZE;
        const screenY = y * TILE_SIZE;

        if (type === 'water') {
            ctx.drawImage(textures['water'], screenX, screenY);
        } else {
            // Рисуем траву как подложку везде
            ctx.drawImage(textures['grass'], screenX, screenY);
        }

        if (type === 'tree') {
            // Y сортировки - низ спрайта. Дерево выше тайла, корректируем Y отрисовки в drawImage, 
            // но в renderList кладем координату основания.
            // Текстура дерева 40x60 (высокая)
            renderList.push({ y: screenY + TILE_SIZE, type: 'tree', data: { x: screenX, y: screenY - 20 } });
        } else if (type === 'stone') {
            renderList.push({ y: screenY + TILE_SIZE, type: 'stone', data: { x: screenX, y: screenY } });
        }
    }
  }

  // 2. Добавляем игроков
  for (const id in players) {
      const p = players[id];
      renderList.push({ y: p.y + 12, type: 'player', data: { player: p, isLocal: id === myId } });
  }

  // 3. Сортировка по глубине (Y)
  renderList.sort((a, b) => a.y - b.y);

  // 4. Отрисовка объектов
  for (const obj of renderList) {
      if (obj.type === 'tree') {
          ctx.drawImage(textures['tree'], obj.data.x, obj.data.y);
      } else if (obj.type === 'stone') {
          ctx.drawImage(textures['stone'], obj.data.x, obj.data.y);
      } else if (obj.type === 'player') {
          drawPlayerPixel(ctx, obj.data.player, obj.data.isLocal);
      }
  }

  // Виньетка (затемнение по краям для атмосферы)
  // Рисуем в координатах экрана, поэтому restore
  ctx.restore();

  const gradient = ctx.createRadialGradient(
      canvas.width / 2, canvas.height / 2, canvas.height / 3,
      canvas.width / 2, canvas.height / 2, canvas.height
  );
  gradient.addColorStop(0, 'rgba(0,0,0,0)');
  gradient.addColorStop(1, 'rgba(0,0,0,0.6)');

  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, canvas.width, canvas.height);
}

// game.ts: Управляет отрисовкой игрового мира в стиле Bright & Vivid (Stardew Valley like).
import { Player, Players, WorldMap, TileType } from './types';

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;

export const TILE_SIZE = 40;
let world: WorldMap = {};

// Кэш сгенерированных текстур
const textures: Record<string, HTMLCanvasElement> = {};

// --- ГЕНЕРАЦИЯ ТЕКСТУР (PIXEL ART) ---

/**
 * Рисует прямоугольник с обводкой (для пиксель-арта)
 */
function drawRectWithOutline(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, fill: string, border: string) {
    ctx.fillStyle = border;
    ctx.fillRect(x - 2, y - 2, w + 4, h + 4); // Обводка
    ctx.fillStyle = fill;
    ctx.fillRect(x, y, w, h); // Заливка
}

function generateTextures() {
    // 1. Трава (Яркая, солнечная)
    const grassC = document.createElement('canvas');
    grassC.width = TILE_SIZE;
    grassC.height = TILE_SIZE;
    const gCtx = grassC.getContext('2d')!;

    // База - Лаймовый зеленый
    gCtx.fillStyle = '#7CFC00'; // LawnGreen
    gCtx.fillRect(0, 0, TILE_SIZE, TILE_SIZE);

    // Редкие травинки (аккуратный шум)
    gCtx.fillStyle = '#66CD00'; // Чуть темнее
    for(let i=0; i<8; i++) {
        const x = Math.floor(Math.random() * (TILE_SIZE/2)) * 2;
        const y = Math.floor(Math.random() * (TILE_SIZE/2)) * 2;
        gCtx.fillRect(x, y, 2, 2);
    }
    // Пару цветочков
    if (Math.random() > 0.5) {
        gCtx.fillStyle = '#FFD700'; // Gold
        gCtx.fillRect(10, 10, 2, 2);
    }

    textures['grass'] = grassC;

    // 2. Вода (Тропическая лагуна)
    const waterC = document.createElement('canvas');
    waterC.width = TILE_SIZE;
    waterC.height = TILE_SIZE;
    const wCtx = waterC.getContext('2d')!;

    wCtx.fillStyle = '#00BFFF'; // DeepSkyBlue
    wCtx.fillRect(0, 0, TILE_SIZE, TILE_SIZE);

    // Блики
    wCtx.fillStyle = '#87CEFA'; // LightSkyBlue
    wCtx.fillRect(5, 5, 10, 2);
    wCtx.fillRect(20, 15, 8, 2);
    wCtx.fillStyle = '#FFFFFF';
    wCtx.fillRect(6, 6, 2, 2);

    textures['water'] = waterC;

    // 3. Камень (Светлый, с обводкой)
    const stoneC = document.createElement('canvas');
    stoneC.width = TILE_SIZE;
    stoneC.height = TILE_SIZE;
    const sCtx = stoneC.getContext('2d')!;

    // Тень под камнем
    sCtx.fillStyle = 'rgba(0,0,0,0.2)';
    sCtx.beginPath();
    sCtx.ellipse(TILE_SIZE/2, TILE_SIZE - 5, 15, 5, 0, 0, Math.PI*2);
    sCtx.fill();

    // Сам камень
    // Обводка
    sCtx.fillStyle = '#2F4F4F'; // DarkSlateGray
    sCtx.fillRect(6, 8, TILE_SIZE-12, TILE_SIZE-14);

    // Тело
    sCtx.fillStyle = '#D3D3D3'; // LightGray
    sCtx.fillRect(8, 10, TILE_SIZE-16, TILE_SIZE-18);

    // Хайлайт (свет сверху)
    sCtx.fillStyle = '#FFFFFF';
    sCtx.fillRect(10, 12, 4, 4);

    textures['stone'] = stoneC;

    // 4. Дерево (Большое, пушистое, яркое)
    const treeC = document.createElement('canvas');
    treeC.width = 60; // Шире тайла
    treeC.height = 80; // Выше тайла
    const tCtx = treeC.getContext('2d')!;

    // Тень
    tCtx.fillStyle = 'rgba(0,0,0,0.2)';
    tCtx.beginPath();
    tCtx.ellipse(30, 75, 20, 6, 0, 0, Math.PI*2);
    tCtx.fill();

    // Ствол
    tCtx.fillStyle = '#4a332a'; // Dark Brown Outline
    tCtx.fillRect(24, 50, 12, 25); 
    tCtx.fillStyle = '#8D6E63'; // Brown Body
    tCtx.fillRect(26, 52, 8, 23);

    // Крона (Облачко)
    // Функция для рисования блока листвы с обводкой
    const drawLeafBlock = (cx: number, cy: number, r: number) => {
        // Outline
        tCtx.fillStyle = '#006400'; // DarkGreen
        tCtx.fillRect(cx - r - 2, cy - r - 2, r*2 + 4, r*2 + 4);
    };

    const drawLeafFill = (cx: number, cy: number, r: number) => {
         // Fill
        tCtx.fillStyle = '#32CD32'; // LimeGreen
        tCtx.fillRect(cx - r, cy - r, r*2, r*2);
        // Highlight
        tCtx.fillStyle = '#90EE90'; // LightGreen
        tCtx.fillRect(cx - r + 2, cy - r + 2, 4, 4);
    };

    // Рисуем обводку всей кроны (грубо, через наложение квадратов)
    drawLeafBlock(30, 30, 18); // Center
    drawLeafBlock(15, 40, 12); // Left
    drawLeafBlock(45, 40, 12); // Right
    drawLeafBlock(30, 15, 12); // Top

    // Рисуем заливку
    drawLeafFill(30, 30, 18);
    drawLeafFill(15, 40, 12);
    drawLeafFill(45, 40, 12);
    drawLeafFill(30, 15, 12);

    textures['tree'] = treeC;
}


/**
 * Инициализирует игровой холст и генерирует начальную область мира.
 */
export function init(canvasElement: HTMLCanvasElement, player: Player) {
  canvas = canvasElement;
  ctx = canvas.getContext('2d');

  // Pixel Art режим
  if (ctx) {
      ctx.imageSmoothingEnabled = false;
  }

  generateTextures();
  generateWorld(player.x, player.y);
}

/**
 * Генерирует мир.
 */
function generateWorld(playerX: number, playerY: number) {
    world = {}; 
    const playerTileX = Math.floor(playerX / TILE_SIZE);
    const playerTileY = Math.floor(playerY / TILE_SIZE);

    const WORLD_RADIUS = 60; 
    for (let x = playerTileX - WORLD_RADIUS; x < playerTileX + WORLD_RADIUS; x++) {
        for (let y = playerTileY - WORLD_RADIUS; y < playerTileY + WORLD_RADIUS; y++) {
            const key = `${x},${y}`;
            const dist = Math.sqrt(Math.pow(playerTileX - x, 2) + Math.pow(playerTileY - y, 2));

            if (dist < 4) {
                world[key] = 'grass';
                continue;
            }

            const noise = Math.sin(x * 0.3) * Math.cos(y * 0.3);
            const rand = Math.random();

            if (noise > 0.8) {
                world[key] = 'water';
            } else if (rand < 0.08) { // Чуть реже деревья, они теперь большие
                world[key] = 'tree';
            } else if (rand < 0.1) {
                world[key] = 'stone';
            } else {
                world[key] = 'grass';
            }
        }
    }
}

export function getTile(tileX: number, tileY: number): TileType {
    return world[`${Math.floor(tileX)},${Math.floor(tileY)}`] || 'grass';
}

export function destroyTile(tileX: number, tileY: number) {
    world[`${tileX},${tileY}`] = 'grass';
}

export function canMoveTo(x: number, y: number, width: number, height: number): boolean {
    const padding = 12; 
    const checkWidth = width - padding;
    const checkHeight = height - padding;

    const corners = [
        { x: x - checkWidth / 2, y: y - checkHeight / 2 + 5 },
        { x: x + checkWidth / 2, y: y - checkHeight / 2 + 5 },
        { x: x - checkWidth / 2, y: y + checkHeight / 2 }, 
        { x: x + checkWidth / 2, y: y + checkHeight / 2 }, 
    ];

    for (const corner of corners) {
        const tileX = Math.floor(corner.x / TILE_SIZE);
        const tileY = Math.floor(corner.y / TILE_SIZE);
        const tileType = getTile(tileX, tileY);
        if (tileType === 'tree' || tileType === 'stone' || tileType === 'water') {
            return false;
        }
    }
    return true;
}

// --- ОТРИСОВКА ---

function drawPlayerPixel(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean) {
    const px = Math.floor(player.x);
    const py = Math.floor(player.y);

    // Тень
    ctx.fillStyle = 'rgba(0,0,0,0.2)';
    ctx.beginPath();
    ctx.ellipse(px, py + 14, 12, 4, 0, 0, Math.PI*2);
    ctx.fill();

    const w = 24;
    const h = 24;
    const x = px - w/2;
    const y = py - h + 10; // Поднимаем спрайт, чтобы ноги были в точке привязки

    // 1. ОБВОДКА (Черная, жирная)
    ctx.fillStyle = '#000000';
    ctx.fillRect(x - 2, y - 2, w + 4, h + 4);

    // 2. ТЕЛО
    ctx.fillStyle = player.color;
    ctx.fillRect(x, y, w, h);

    // 3. ДЕТАЛИ (Лицо)
    // Кожа
    ctx.fillStyle = '#FFE0BD'; // Light Skin
    ctx.fillRect(x + 6, y + 4, 12, 10);

    // Глаза
    ctx.fillStyle = '#000';
    ctx.fillRect(x + 8, y + 8, 2, 4);
    ctx.fillRect(x + 14, y + 8, 2, 4);

    // Никнейм
    if (!isLocal) {
        ctx.fillStyle = '#fff';
        ctx.strokeStyle = '#000';
        ctx.lineWidth = 2;
        ctx.font = 'bold 12px sans-serif';
        ctx.textAlign = 'center';
        ctx.strokeText(player.nickname, px, y - 10);
        ctx.fillText(player.nickname, px, y - 10);
    } else {
        // Указатель над собой
        ctx.fillStyle = '#FFD700';
        ctx.beginPath();
        ctx.moveTo(px, y - 15);
        ctx.lineTo(px - 5, y - 25);
        ctx.lineTo(px + 5, y - 25);
        ctx.fill();
    }
}

interface RenderObject {
    y: number; // Z-index
    type: 'tree' | 'stone' | 'player';
    data: any;
}

export function renderGame(players: Players, myId: string) {
  if (!ctx || !canvas) return;
  const me = players[myId];
  if (!me) return;

  ctx.imageSmoothingEnabled = false;

  const cameraX = Math.floor(me.x - canvas.width / 2);
  const cameraY = Math.floor(me.y - canvas.height / 2);

  // Яркий фон (Заполняем все зеленой травой по умолчанию, чтобы не было дырок)
  ctx.fillStyle = '#7CFC00'; 
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  ctx.save();
  ctx.translate(-cameraX, -cameraY);

  const startTileX = Math.floor(cameraX / TILE_SIZE) - 1;
  const endTileX = startTileX + Math.ceil(canvas.width / TILE_SIZE) + 2;
  const startTileY = Math.floor(cameraY / TILE_SIZE) - 1;
  const endTileY = startTileY + Math.ceil(canvas.height / TILE_SIZE) + 2;

  const renderList: RenderObject[] = [];

  // 1. Рисуем слой земли
  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const type = getTile(x, y);
        const screenX = x * TILE_SIZE;
        const screenY = y * TILE_SIZE;

        if (type === 'water') {
            ctx.drawImage(textures['water'], screenX, screenY);
        } else {
            ctx.drawImage(textures['grass'], screenX, screenY);
        }

        if (type === 'tree') {
            // Дерево большое (60x80), центрируем по горизонтали относительно тайла (40px)
            // (60 - 40) / 2 = 10 сдвиг влево
            // Сдвиг вверх, чтобы основание ствола было внизу тайла
            renderList.push({ y: screenY + TILE_SIZE, type: 'tree', data: { x: screenX - 10, y: screenY - 40 } });
        } else if (type === 'stone') {
            renderList.push({ y: screenY + TILE_SIZE, type: 'stone', data: { x: screenX, y: screenY } });
        }
    }
  }

  // 2. Добавляем игроков
  for (const id in players) {
      const p = players[id];
      renderList.push({ y: p.y + 10, type: 'player', data: { player: p, isLocal: id === myId } });
  }

  // 3. Сортировка по Y (чтобы прятаться за деревьями)
  renderList.sort((a, b) => a.y - b.y);

  // 4. Отрисовка объектов
  for (const obj of renderList) {
      if (obj.type === 'tree') {
          ctx.drawImage(textures['tree'], obj.data.x, obj.data.y);
      } else if (obj.type === 'stone') {
          ctx.drawImage(textures['stone'], obj.data.x, obj.data.y);
      } else if (obj.type === 'player') {
          drawPlayerPixel(ctx, obj.data.player, obj.data.isLocal);
      }
  }

  ctx.restore();
  // Убрали виньетку, чтобы было ярко!
}

// game.ts: Управляет отрисовкой игрового мира в стиле "Semi-Realistic Vector" (Google Emoji Style).
import { Player, Players, WorldMap, TileType } from './types';

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;

export const TILE_SIZE = 40;
let world: WorldMap = {};

// Кэш сгенерированных текстур
const textures: Record<string, HTMLCanvasElement> = {};

// --- ГЕНЕРАЦИЯ ТЕКСТУР (VECTOR GRADIENTS) ---

function generateTextures() {
    // 1. Трава (Natural & Soft)
    const grassC = document.createElement('canvas');
    grassC.width = TILE_SIZE;
    grassC.height = TILE_SIZE;
    const gCtx = grassC.getContext('2d')!;

    // Базовый фон
    gCtx.fillStyle = '#4E7C48'; // Natural Green
    gCtx.fillRect(0, 0, TILE_SIZE, TILE_SIZE);

    // Мягкая текстура земли (пятна)
    gCtx.fillStyle = '#3A5F36';
    gCtx.globalAlpha = 0.3;
    for(let i=0; i<3; i++) {
        const x = Math.random() * TILE_SIZE;
        const y = Math.random() * TILE_SIZE;
        const r = 2 + Math.random() * 5;
        gCtx.beginPath();
        gCtx.arc(x, y, r, 0, Math.PI*2);
        gCtx.fill();
    }
    gCtx.globalAlpha = 1.0;

    textures['grass'] = grassC;

    // 2. Вода (Deep & Glossy)
    const waterC = document.createElement('canvas');
    waterC.width = TILE_SIZE;
    waterC.height = TILE_SIZE;
    const wCtx = waterC.getContext('2d')!;

    // Градиент глубины
    const waterGrad = wCtx.createLinearGradient(0, 0, TILE_SIZE, TILE_SIZE);
    waterGrad.addColorStop(0, '#2B65EC'); // Ocean Blue
    waterGrad.addColorStop(1, '#1F45FC'); // Deep Blue
    wCtx.fillStyle = waterGrad;
    wCtx.fillRect(0, 0, TILE_SIZE, TILE_SIZE);

    // Блики (Гладкая поверхность)
    wCtx.fillStyle = 'rgba(255, 255, 255, 0.2)';
    wCtx.beginPath();
    wCtx.ellipse(TILE_SIZE * 0.3, TILE_SIZE * 0.4, 8, 3, Math.PI / 6, 0, Math.PI * 2);
    wCtx.fill();

    wCtx.beginPath();
    wCtx.ellipse(TILE_SIZE * 0.7, TILE_SIZE * 0.7, 5, 2, -Math.PI / 6, 0, Math.PI * 2);
    wCtx.fill();

    textures['water'] = waterC;

    // 3. Камень (Smooth & Volumetric)
    const stoneC = document.createElement('canvas');
    stoneC.width = TILE_SIZE;
    stoneC.height = TILE_SIZE;
    const sCtx = stoneC.getContext('2d')!;

    // Тень (Мягкая)
    sCtx.fillStyle = 'rgba(0,0,0,0.2)';
    sCtx.filter = 'blur(2px)'; // Размытие тени
    sCtx.beginPath();
    sCtx.ellipse(TILE_SIZE/2, TILE_SIZE - 6, 14, 5, 0, 0, Math.PI*2);
    sCtx.fill();
    sCtx.filter = 'none';

    // Тело камня (Градиент)
    // Рисуем слегка искаженный круг
    const cx = TILE_SIZE/2;
    const cy = TILE_SIZE/2 + 2;
    const stoneGrad = sCtx.createLinearGradient(0, 0, TILE_SIZE, TILE_SIZE);
    stoneGrad.addColorStop(0, '#D1D5DB'); // Gray-300 (Light Top-Left)
    stoneGrad.addColorStop(1, '#4B5563'); // Gray-600 (Dark Bottom-Right)

    sCtx.fillStyle = stoneGrad;
    sCtx.beginPath();
    sCtx.moveTo(cx - 12, cy);
    sCtx.bezierCurveTo(cx - 12, cy - 10, cx + 12, cy - 10, cx + 14, cy); // Top curve
    sCtx.bezierCurveTo(cx + 14, cy + 10, cx - 12, cy + 10, cx - 12, cy); // Bottom curve
    sCtx.fill();

    // Блик (Specular Highlight) для эффекта "гладкости"
    const highlightGrad = sCtx.createRadialGradient(cx - 5, cy - 5, 1, cx - 5, cy - 5, 6);
    highlightGrad.addColorStop(0, 'rgba(255, 255, 255, 0.6)');
    highlightGrad.addColorStop(1, 'rgba(255, 255, 255, 0.0)');
    sCtx.fillStyle = highlightGrad;
    sCtx.beginPath();
    sCtx.arc(cx - 5, cy - 5, 6, 0, Math.PI*2);
    sCtx.fill();

    textures['stone'] = stoneC;

    // 4. Дерево (Emoji Style)
    const treeC = document.createElement('canvas');
    treeC.width = 60; 
    treeC.height = 80; 
    const tCtx = treeC.getContext('2d')!;

    // Тень
    tCtx.fillStyle = 'rgba(0,0,0,0.2)';
    tCtx.filter = 'blur(3px)';
    tCtx.beginPath();
    tCtx.ellipse(30, 72, 18, 6, 0, 0, Math.PI*2);
    tCtx.fill();
    tCtx.filter = 'none';

    // Ствол (Цилиндрический градиент)
    const trunkGrad = tCtx.createLinearGradient(15, 0, 45, 0); // Horizontal gradient
    trunkGrad.addColorStop(0, '#3E2723'); // Dark
    trunkGrad.addColorStop(0.3, '#5D4037'); // Lighter center
    trunkGrad.addColorStop(1, '#281815'); // Darkest edge

    tCtx.fillStyle = trunkGrad;
    tCtx.beginPath();
    tCtx.moveTo(24, 40);
    tCtx.lineTo(36, 40);
    tCtx.lineTo(38, 75); // Чуть шире к низу
    tCtx.lineTo(22, 75);
    tCtx.fill();

    // Крона (Кластеры шаров)
    const drawLeafBall = (x: number, y: number, r: number) => {
        const ballGrad = tCtx.createRadialGradient(x - r/3, y - r/3, r/5, x, y, r);
        ballGrad.addColorStop(0, '#84CC16'); // Lime-500 (Light Top-Left)
        ballGrad.addColorStop(1, '#3F6212'); // Lime-900 (Dark edges)

        tCtx.fillStyle = ballGrad;
        tCtx.beginPath();
        tCtx.arc(x, y, r, 0, Math.PI*2);
        tCtx.fill();
    };

    // Рисуем 3 шара, создавая объемную крону
    drawLeafBall(30, 25, 20); // Top Center
    drawLeafBall(18, 45, 16); // Left
    drawLeafBall(42, 45, 16); // Right

    textures['tree'] = treeC;
}

/**
 * Инициализация
 */
export function init(canvasElement: HTMLCanvasElement, player: Player) {
  canvas = canvasElement;
  ctx = canvas.getContext('2d');

  // Включаем сглаживание для векторного стиля
  if (ctx) {
      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';
  }

  generateTextures();
  generateWorld(player.x, player.y);
}

/**
 * Генерация мира
 */
function generateWorld(playerX: number, playerY: number) {
    world = {}; 
    const playerTileX = Math.floor(playerX / TILE_SIZE);
    const playerTileY = Math.floor(playerY / TILE_SIZE);

    const WORLD_RADIUS = 60; 
    for (let x = playerTileX - WORLD_RADIUS; x < playerTileX + WORLD_RADIUS; x++) {
        for (let y = playerTileY - WORLD_RADIUS; y < playerTileY + WORLD_RADIUS; y++) {
            const key = `${x},${y}`;
            const dist = Math.sqrt(Math.pow(playerTileX - x, 2) + Math.pow(playerTileY - y, 2));

            if (dist < 4) {
                world[key] = 'grass';
                continue;
            }

            // Используем Math.sin для создания более органичных "островов"
            const noise = Math.sin(x * 0.2) * Math.cos(y * 0.2) + Math.random() * 0.2;
            const rand = Math.random();

            if (noise > 0.7) {
                world[key] = 'water';
            } else if (rand < 0.08) { 
                world[key] = 'tree';
            } else if (rand < 0.05) {
                world[key] = 'stone';
            } else {
                world[key] = 'grass';
            }
        }
    }
}

export function getTile(tileX: number, tileY: number): TileType {
    return world[`${Math.floor(tileX)},${Math.floor(tileY)}`] || 'grass';
}

export function destroyTile(tileX: number, tileY: number) {
    world[`${tileX},${tileY}`] = 'grass';
}

export function canMoveTo(x: number, y: number, width: number, height: number): boolean {
    const padding = 15; // Больше отступ для "толстых" объектов
    const checkWidth = width - padding;
    const checkHeight = height - padding;

    const corners = [
        { x: x - checkWidth / 2, y: y - checkHeight / 2 + 5 },
        { x: x + checkWidth / 2, y: y - checkHeight / 2 + 5 },
        { x: x - checkWidth / 2, y: y + checkHeight / 2 }, 
        { x: x + checkWidth / 2, y: y + checkHeight / 2 }, 
    ];

    for (const corner of corners) {
        const tileX = Math.floor(corner.x / TILE_SIZE);
        const tileY = Math.floor(corner.y / TILE_SIZE);
        const tileType = getTile(tileX, tileY);
        if (tileType === 'tree' || tileType === 'stone' || tileType === 'water') {
            return false;
        }
    }
    return true;
}

// --- ОТРИСОВКА ИГРОКА ---

function drawPlayerVector(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean) {
    const x = player.x;
    const y = player.y;

    // Тень
    ctx.fillStyle = 'rgba(0,0,0,0.2)';
    ctx.filter = 'blur(3px)';
    ctx.beginPath();
    ctx.ellipse(x, y + 10, 14, 6, 0, 0, Math.PI*2);
    ctx.fill();
    ctx.filter = 'none';

    // Тело (Закругленный прямоугольник с градиентом)
    const bodyW = 20;
    const bodyH = 24;

    // Создаем градиент для одежды (Свет слева-сверху)
    const bodyGrad = ctx.createLinearGradient(x - bodyW/2, y - bodyH, x + bodyW/2, y);
    // Парсим цвет игрока (предполагаем HSL или Hex). 
    // Для простоты используем его как базу, но лучше было бы делать темнее/светлее.
    // Тут просто накладываем полупрозрачный градиент поверх цвета игрока.

    ctx.fillStyle = player.color; 

    // Рисуем базу тела
    ctx.beginPath();
    ctx.roundRect(x - bodyW/2, y - bodyH + 5, bodyW, bodyH, 8);
    ctx.fill();

    // Накладываем градиент тени поверх
    const shadowOverlay = ctx.createLinearGradient(x - bodyW/2, y - bodyH, x + bodyW/2, y + 5);
    shadowOverlay.addColorStop(0, 'rgba(255,255,255,0.2)');
    shadowOverlay.addColorStop(1, 'rgba(0,0,0,0.3)');
    ctx.fillStyle = shadowOverlay;
    ctx.fill();

    // Голова (Круг с радиальным градиентом - Капюшон)
    const headR = 11;
    const headY = y - bodyH + 5;

    const headGrad = ctx.createRadialGradient(x - 3, headY - 3, 2, x, headY, headR);
    headGrad.addColorStop(0, '#F3F4F6'); // Светлый блик
    headGrad.addColorStop(1, '#9CA3AF'); // Серый капюшон (нейтральный)

    // Если это локальный игрок, делаем капюшон золотым
    if (isLocal) {
        const goldGrad = ctx.createRadialGradient(x - 3, headY - 3, 2, x, headY, headR);
        goldGrad.addColorStop(0, '#FDE047'); 
        goldGrad.addColorStop(1, '#D97706');
        ctx.fillStyle = goldGrad;
    } else {
        // Цвет игрока для головы, но темнее
        ctx.fillStyle = player.color;
    }

    ctx.beginPath();
    ctx.arc(x, headY, headR, 0, Math.PI*2);
    ctx.fill();

    // "Лицо" (Просто тень внутри капюшона)
    ctx.fillStyle = 'rgba(0,0,0,0.5)';
    ctx.beginPath();
    ctx.arc(x, headY + 2, 6, 0, Math.PI*2);
    ctx.fill();


    // Никнейм (Аккуратный, без обводки, с тенью)
    if (!isLocal) {
        ctx.fillStyle = '#FFFFFF';
        ctx.shadowColor = 'rgba(0,0,0,0.5)';
        ctx.shadowBlur = 4;
        ctx.font = 'bold 12px "Segoe UI", sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(player.nickname, x, y - 35);
        ctx.shadowBlur = 0;
    }
}

interface RenderObject {
    y: number; // Z-index
    type: 'tree' | 'stone' | 'player';
    data: any;
}

export function renderGame(players: Players, myId: string) {
  if (!ctx || !canvas) return;
  const me = players[myId];
  if (!me) return;

  // Чистый фон
  ctx.fillStyle = '#4E7C48'; 
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  const cameraX = me.x - canvas.width / 2;
  const cameraY = me.y - canvas.height / 2;

  ctx.save();
  ctx.translate(-cameraX, -cameraY);

  const startTileX = Math.floor(cameraX / TILE_SIZE) - 1;
  const endTileX = startTileX + Math.ceil(canvas.width / TILE_SIZE) + 2;
  const startTileY = Math.floor(cameraY / TILE_SIZE) - 1;
  const endTileY = startTileY + Math.ceil(canvas.height / TILE_SIZE) + 2;

  const renderList: RenderObject[] = [];

  // 1. Рисуем слой земли
  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const type = getTile(x, y);
        const screenX = x * TILE_SIZE;
        const screenY = y * TILE_SIZE;

        if (type === 'water') {
            ctx.drawImage(textures['water'], screenX, screenY);
        } else {
            // Трава рисуется везде как база
            ctx.drawImage(textures['grass'], screenX, screenY);
        }

        if (type === 'tree') {
            // Дерево: x - смещение влево (так как оно 60px шириной), y - смещение вверх
            renderList.push({ y: screenY + TILE_SIZE, type: 'tree', data: { x: screenX - 10, y: screenY - 40 } });
        } else if (type === 'stone') {
            renderList.push({ y: screenY + TILE_SIZE, type: 'stone', data: { x: screenX, y: screenY } });
        }
    }
  }

  // 2. Добавляем игроков
  for (const id in players) {
      const p = players[id];
      renderList.push({ y: p.y, type: 'player', data: { player: p, isLocal: id === myId } });
  }

  // 3. Сортировка по глубине
  renderList.sort((a, b) => a.y - b.y);

  // 4. Отрисовка объектов
  for (const obj of renderList) {
      if (obj.type === 'tree') {
          ctx.drawImage(textures['tree'], obj.data.x, obj.data.y);
      } else if (obj.type === 'stone') {
          ctx.drawImage(textures['stone'], obj.data.x, obj.data.y);
      } else if (obj.type === 'player') {
          drawPlayerVector(ctx, obj.data.player, obj.data.isLocal);
      }
  }

  ctx.restore();
}

// game.ts: Управляет отрисовкой игрового мира в стиле "Semi-Realistic Vector" (Google Emoji Style).
import { Player, Players, WorldMap, TileType } from './types';

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;

export const TILE_SIZE = 40;
let world: WorldMap = {};

// Кэш сгенерированных текстур
const textures: Record<string, HTMLCanvasElement> = {};

// --- ГЕНЕРАЦИЯ ТЕКСТУР (VECTOR GRADIENTS) ---

function generateTextures() {
    // 1. Трава (Natural & Soft)
    const grassC = document.createElement('canvas');
    grassC.width = TILE_SIZE;
    grassC.height = TILE_SIZE;
    const gCtx = grassC.getContext('2d')!;

    // Базовый фон
    gCtx.fillStyle = '#4E7C48'; // Natural Green
    gCtx.fillRect(0, 0, TILE_SIZE, TILE_SIZE);

    // Мягкая текстура земли (пятна)
    gCtx.fillStyle = '#3A5F36';
    gCtx.globalAlpha = 0.3;
    for(let i=0; i<3; i++) {
        const x = Math.random() * TILE_SIZE;
        const y = Math.random() * TILE_SIZE;
        const r = 2 + Math.random() * 5;
        gCtx.beginPath();
        gCtx.arc(x, y, r, 0, Math.PI*2);
        gCtx.fill();
    }
    gCtx.globalAlpha = 1.0;

    textures['grass'] = grassC;

    // 2. Вода (Deep & Glossy)
    const waterC = document.createElement('canvas');
    waterC.width = TILE_SIZE;
    waterC.height = TILE_SIZE;
    const wCtx = waterC.getContext('2d')!;

    // Градиент глубины
    const waterGrad = wCtx.createLinearGradient(0, 0, TILE_SIZE, TILE_SIZE);
    waterGrad.addColorStop(0, '#2B65EC'); // Ocean Blue
    waterGrad.addColorStop(1, '#1F45FC'); // Deep Blue
    wCtx.fillStyle = waterGrad;
    wCtx.fillRect(0, 0, TILE_SIZE, TILE_SIZE);

    // Блики (Гладкая поверхность)
    wCtx.fillStyle = 'rgba(255, 255, 255, 0.2)';
    wCtx.beginPath();
    wCtx.ellipse(TILE_SIZE * 0.3, TILE_SIZE * 0.4, 8, 3, Math.PI / 6, 0, Math.PI * 2);
    wCtx.fill();

    wCtx.beginPath();
    wCtx.ellipse(TILE_SIZE * 0.7, TILE_SIZE * 0.7, 5, 2, -Math.PI / 6, 0, Math.PI * 2);
    wCtx.fill();

    textures['water'] = waterC;

    // 3. Камень (Smooth & Volumetric)
    const stoneC = document.createElement('canvas');
    stoneC.width = TILE_SIZE;
    stoneC.height = TILE_SIZE;
    const sCtx = stoneC.getContext('2d')!;

    // Тень (Мягкая)
    sCtx.fillStyle = 'rgba(0,0,0,0.2)';
    sCtx.filter = 'blur(2px)'; // Размытие тени
    sCtx.beginPath();
    sCtx.ellipse(TILE_SIZE/2, TILE_SIZE - 6, 14, 5, 0, 0, Math.PI*2);
    sCtx.fill();
    sCtx.filter = 'none';

    // Тело камня (Градиент)
    // Рисуем слегка искаженный круг
    const cx = TILE_SIZE/2;
    const cy = TILE_SIZE/2 + 2;
    const stoneGrad = sCtx.createLinearGradient(0, 0, TILE_SIZE, TILE_SIZE);
    stoneGrad.addColorStop(0, '#D1D5DB'); // Gray-300 (Light Top-Left)
    stoneGrad.addColorStop(1, '#4B5563'); // Gray-600 (Dark Bottom-Right)

    sCtx.fillStyle = stoneGrad;
    sCtx.beginPath();
    sCtx.moveTo(cx - 12, cy);
    sCtx.bezierCurveTo(cx - 12, cy - 10, cx + 12, cy - 10, cx + 14, cy); // Top curve
    sCtx.bezierCurveTo(cx + 14, cy + 10, cx - 12, cy + 10, cx - 12, cy); // Bottom curve
    sCtx.fill();

    // Блик (Specular Highlight) для эффекта "гладкости"
    const highlightGrad = sCtx.createRadialGradient(cx - 5, cy - 5, 1, cx - 5, cy - 5, 6);
    highlightGrad.addColorStop(0, 'rgba(255, 255, 255, 0.6)');
    highlightGrad.addColorStop(1, 'rgba(255, 255, 255, 0.0)');
    sCtx.fillStyle = highlightGrad;
    sCtx.beginPath();
    sCtx.arc(cx - 5, cy - 5, 6, 0, Math.PI*2);
    sCtx.fill();

    textures['stone'] = stoneC;

    // 4. Дерево (Mighty Oak Style)
    const treeW = 80; // Широкое
    const treeH = 100; // Высокое
    const treeC = document.createElement('canvas');
    treeC.width = treeW; 
    treeC.height = treeH; 
    const tCtx = treeC.getContext('2d')!;

    const centerX = treeW / 2;
    const bottomY = treeH - 5;

    // Тень (Большая, под всем деревом)
    tCtx.fillStyle = 'rgba(0,0,0,0.2)';
    tCtx.filter = 'blur(4px)';
    tCtx.beginPath();
    tCtx.ellipse(centerX, bottomY - 5, 25, 8, 0, 0, Math.PI*2);
    tCtx.fill();
    tCtx.filter = 'none';

    // СТВОЛ (Толстый, матовый, темный шоколад)
    tCtx.fillStyle = '#3E2723'; // Dark Chocolate Matte
    tCtx.beginPath();
    // Основание (Корни)
    tCtx.moveTo(centerX - 12, bottomY);
    tCtx.quadraticCurveTo(centerX - 8, bottomY - 10, centerX - 8, bottomY - 30); // Left side
    tCtx.lineTo(centerX + 8, bottomY - 30); // Top of visible trunk
    tCtx.quadraticCurveTo(centerX + 8, bottomY - 10, centerX + 12, bottomY); // Right side
    tCtx.fill();

    // КРОНА (Раскидистое облако)
    // Координаты кругов относительно центра кроны
    const canopyCenterY = treeH / 2 - 10;
    const leaves = [
        { x: 0, y: 0, r: 28 },    // Center Main
        { x: -20, y: 10, r: 22 }, // Bottom Left
        { x: 20, y: 10, r: 22 },  // Bottom Right
        { x: -15, y: -15, r: 24 },// Top Left
        { x: 15, y: -15, r: 24 }, // Top Right
        { x: 0, y: -25, r: 20 },  // Top Tip
    ];

    // 1. Слой теней (Темно-зеленый фон кроны)
    tCtx.fillStyle = '#1B5E20'; // Deep Green Shadow
    leaves.forEach(leaf => {
        tCtx.beginPath();
        tCtx.arc(centerX + leaf.x, canopyCenterY + leaf.y + 3, leaf.r, 0, Math.PI*2);
        tCtx.fill();
    });

    // 2. Основной объем (Градиентные шары)
    leaves.forEach(leaf => {
        const lx = centerX + leaf.x;
        const ly = canopyCenterY + leaf.y;

        // Смещенный градиент для объема (свет падает сверху-слева)
        const grad = tCtx.createRadialGradient(lx - 10, ly - 10, 5, lx, ly, leaf.r);
        grad.addColorStop(0, '#66BB6A'); // Light Green Highlight
        grad.addColorStop(0.5, '#43A047'); // Base Green
        grad.addColorStop(1, '#2E7D32'); // Darker Edge

        tCtx.fillStyle = grad;
        tCtx.beginPath();
        tCtx.arc(lx, ly, leaf.r, 0, Math.PI*2);
        tCtx.fill();
    });

    // 3. Детализация (Шум листвы)
    // Рисуем светлые точки поверх кроны
    tCtx.fillStyle = '#A5D6A7'; // Pale Green dots
    for(let i=0; i<60; i++) {
        // Случайная точка внутри эллипса кроны
        const rx = (Math.random() - 0.5) * 60;
        const ry = (Math.random() - 0.5) * 50;
        // Простая проверка, чтобы не рисовать в воздухе (в круге радиусом 35 от центра кроны)
        if (rx*rx + ry*ry < 35*35) {
            tCtx.beginPath();
            tCtx.arc(centerX + rx, canopyCenterY + ry, 1.5, 0, Math.PI*2);
            tCtx.fill();
        }
    }

    textures['tree'] = treeC;
}

/**
 * Инициализация
 */
export function init(canvasElement: HTMLCanvasElement, player: Player) {
  canvas = canvasElement;
  ctx = canvas.getContext('2d');

  // Включаем сглаживание для векторного стиля
  if (ctx) {
      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';
  }

  generateTextures();
  generateWorld(player.x, player.y);
}

/**
 * Генерация мира
 */
function generateWorld(playerX: number, playerY: number) {
    world = {}; 
    const playerTileX = Math.floor(playerX / TILE_SIZE);
    const playerTileY = Math.floor(playerY / TILE_SIZE);

    const WORLD_RADIUS = 60; 
    for (let x = playerTileX - WORLD_RADIUS; x < playerTileX + WORLD_RADIUS; x++) {
        for (let y = playerTileY - WORLD_RADIUS; y < playerTileY + WORLD_RADIUS; y++) {
            const key = `${x},${y}`;
            const dist = Math.sqrt(Math.pow(playerTileX - x, 2) + Math.pow(playerTileY - y, 2));

            if (dist < 4) {
                world[key] = 'grass';
                continue;
            }

            // Используем Math.sin для создания более органичных "островов"
            const noise = Math.sin(x * 0.2) * Math.cos(y * 0.2) + Math.random() * 0.2;
            const rand = Math.random();

            if (noise > 0.7) {
                world[key] = 'water';
            } else if (rand < 0.08) { 
                world[key] = 'tree';
            } else if (rand < 0.05) {
                world[key] = 'stone';
            } else {
                world[key] = 'grass';
            }
        }
    }
}

export function getTile(tileX: number, tileY: number): TileType {
    return world[`${Math.floor(tileX)},${Math.floor(tileY)}`] || 'grass';
}

export function destroyTile(tileX: number, tileY: number) {
    world[`${tileX},${tileY}`] = 'grass';
}

export function canMoveTo(x: number, y: number, width: number, height: number): boolean {
    const padding = 15; // Больше отступ для "толстых" объектов
    const checkWidth = width - padding;
    const checkHeight = height - padding;

    const corners = [
        { x: x - checkWidth / 2, y: y - checkHeight / 2 + 5 },
        { x: x + checkWidth / 2, y: y - checkHeight / 2 + 5 },
        { x: x - checkWidth / 2, y: y + checkHeight / 2 }, 
        { x: x + checkWidth / 2, y: y + checkHeight / 2 }, 
    ];

    for (const corner of corners) {
        const tileX = Math.floor(corner.x / TILE_SIZE);
        const tileY = Math.floor(corner.y / TILE_SIZE);
        const tileType = getTile(tileX, tileY);
        if (tileType === 'tree' || tileType === 'stone' || tileType === 'water') {
            return false;
        }
    }
    return true;
}

