// game.ts: Управляет отрисовкой игрового мира в стиле Modern Stylized RPG (2025 Vision).
import { Player, Players, WorldMap, TileType } from './types';

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;

export const TILE_SIZE = 40;
let world: WorldMap = {};

// Кэш текстур
const textures: Record<string, HTMLCanvasElement> = {};

// --- ГЕНЕРАЦИЯ ТЕКСТУР (High Fidelity) ---

function generateTextures() {
    // 1. Трава (Clean & Uniform)
    const grassC = document.createElement('canvas');
    grassC.width = TILE_SIZE;
    grassC.height = TILE_SIZE;
    const gCtx = grassC.getContext('2d')!;

    // Ровный цвет базы (без градиентов) - приятный RPG зеленый
    gCtx.fillStyle = '#4e8c33'; 
    gCtx.fillRect(0, 0, TILE_SIZE, TILE_SIZE);

    // Случайные травинки
    // Рисуем их простыми штрихами, чтобы не перегружать картинку
    const bladeCount = 6; // Количество травинок на тайл

    for(let i=0; i<bladeCount; i++) {
        const x = Math.random() * (TILE_SIZE - 4);
        const y = Math.random() * (TILE_SIZE - 6) + 3;
        const h = 3 + Math.random() * 3; // Высота от 3 до 6 пикселей

        // Травинка (Светлее фона)
        gCtx.fillStyle = '#6ab04c'; 
        gCtx.beginPath();
        gCtx.moveTo(x, y);
        gCtx.lineTo(x + 1, y - h); // Верхушка
        gCtx.lineTo(x + 2, y);
        gCtx.fill();
    }

    textures['grass'] = grassC;

    // 2. Вода (Deep & Reflective)
    const waterC = document.createElement('canvas');
    waterC.width = TILE_SIZE;
    waterC.height = TILE_SIZE;
    const wCtx = waterC.getContext('2d')!;

    // Глубокий океанический градиент
    const waterGrad = wCtx.createRadialGradient(TILE_SIZE/2, TILE_SIZE/2, 0, TILE_SIZE/2, TILE_SIZE/2, TILE_SIZE);
    waterGrad.addColorStop(0, '#4FA4F4'); // Светлее в центре
    waterGrad.addColorStop(1, '#2979FF'); // Глубокий синий
    wCtx.fillStyle = waterGrad;
    wCtx.fillRect(0, 0, TILE_SIZE, TILE_SIZE);

    // Волны (Гладкие линии)
    wCtx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
    wCtx.lineWidth = 1.5;
    wCtx.beginPath();
    wCtx.moveTo(5, 10);
    wCtx.quadraticCurveTo(15, 5, 25, 10);
    wCtx.stroke();

    wCtx.beginPath();
    wCtx.moveTo(15, 30);
    wCtx.quadraticCurveTo(25, 25, 35, 30);
    wCtx.stroke();

    textures['water'] = waterC;

    // 3. Камень (Realistic Rock)
    const stoneC = document.createElement('canvas');
    stoneC.width = TILE_SIZE;
    stoneC.height = TILE_SIZE;
    const sCtx = stoneC.getContext('2d')!;

    const cx = TILE_SIZE / 2;
    const cy = TILE_SIZE / 2 + 5;

    // Тень
    sCtx.fillStyle = 'rgba(0,0,0,0.3)';
    sCtx.beginPath();
    sCtx.ellipse(cx, cy + 10, 15, 6, 0, 0, Math.PI*2);
    sCtx.fill();

    // Форма камня (Сложная)
    sCtx.beginPath();
    sCtx.moveTo(cx - 15, cy + 5);
    sCtx.lineTo(cx - 10, cy - 10); // Left sharp edge
    sCtx.lineTo(cx, cy - 15);      // Top peak
    sCtx.lineTo(cx + 12, cy - 8);  // Right shoulder
    sCtx.lineTo(cx + 15, cy + 5);  // Right base
    sCtx.lineTo(cx, cy + 10);      // Bottom
    sCtx.closePath();

    // Градиентная заливка
    const rockGrad = sCtx.createLinearGradient(0, 0, TILE_SIZE, TILE_SIZE);
    rockGrad.addColorStop(0, '#90A4AE'); // Light Blue Grey
    rockGrad.addColorStop(1, '#546E7A'); // Dark Blue Grey
    sCtx.fillStyle = rockGrad;
    sCtx.fill();

    // Хайлайты (Трещины/Грани)
    sCtx.fillStyle = 'rgba(255,255,255,0.3)';
    sCtx.beginPath();
    sCtx.moveTo(cx - 10, cy - 10);
    sCtx.lineTo(cx, cy - 15);
    sCtx.lineTo(cx + 5, cy - 5);
    sCtx.fill();

    textures['stone'] = stoneC;

    // 4. ДЕРЕВО (HIGH FANTASY STYLE)
    // Огромное, высокое, детализированное
    const treeW = 140; 
    const treeH = 220; // Очень высокое!
    const treeC = document.createElement('canvas');
    treeC.width = treeW; 
    treeC.height = treeH; 
    const tCtx = treeC.getContext('2d')!;

    const tX = treeW / 2;
    const tBaseY = treeH - 15;

    // Тень от всего дерева
    tCtx.fillStyle = 'rgba(0,0,0,0.25)';
    tCtx.filter = 'blur(6px)';
    tCtx.beginPath();
    tCtx.ellipse(tX, tBaseY - 5, 30, 10, 0, 0, Math.PI*2);
    tCtx.fill();
    tCtx.filter = 'none';

    // Ствол (Реалистичный, темный)
    const trunkGrad = tCtx.createLinearGradient(tX - 15, 0, tX + 15, 0);
    trunkGrad.addColorStop(0, '#3E2723'); // Shadow side
    trunkGrad.addColorStop(0.4, '#5D4037'); // Highlight
    trunkGrad.addColorStop(1, '#251714'); // Dark side

    tCtx.fillStyle = trunkGrad;
    tCtx.beginPath();
    // Корни
    tCtx.moveTo(tX - 15, tBaseY); 
    tCtx.quadraticCurveTo(tX - 10, tBaseY - 30, tX - 10, tBaseY - 80); // Left side
    tCtx.lineTo(tX + 10, tBaseY - 80);
    tCtx.quadraticCurveTo(tX + 10, tBaseY - 30, tX + 15, tBaseY); // Right side
    tCtx.fill();

    // КРОНА (Procedural Fluffy Leaves)
    // Рисуем сотню маленьких кружочков, чтобы создать эффект листвы
    const canopyCenterY = tBaseY - 140;

    // Функция рисования пучка листвы
    const drawLeafClump = (lx: number, ly: number, size: number, colorBase: string, colorLight: string) => {
        const grad = tCtx.createRadialGradient(lx - size/3, ly - size/3, size/4, lx, ly, size);
        grad.addColorStop(0, colorLight);
        grad.addColorStop(1, colorBase);
        tCtx.fillStyle = grad;
        tCtx.beginPath();
        tCtx.arc(lx, ly, size, 0, Math.PI*2);
        tCtx.fill();
    };

    // Массив позиций для кроны (формируем форму гриба/дерева)
    const layers = [
        { y: 60, w: 50, count: 12, s: 20, c: '#1B5E20', l: '#2E7D32' }, // Bottom Darkest Layer
        { y: 30, w: 55, count: 14, s: 22, c: '#2E7D32', l: '#43A047' }, // Mid Layer
        { y: 0, w: 45, count: 12, s: 24, c: '#43A047', l: '#66BB6A' },  // Upper Layer
        { y: -30, w: 30, count: 8, s: 22, c: '#66BB6A', l: '#A5D6A7' }  // Top Highlights
    ];

    layers.forEach(layer => {
        for(let i=0; i<layer.count; i++) {
            // Случайное смещение внутри слоя
            const offsetX = (Math.random() - 0.5) * layer.w * 2;
            const offsetY = (Math.random() - 0.5) * 20;

            drawLeafClump(
                tX + offsetX, 
                canopyCenterY + layer.y + offsetY, 
                layer.s + Math.random()*5, 
                layer.c, 
                layer.l
            );
        }
    });

    textures['tree'] = treeC;
}

/**
 * Инициализация
 */
export function init(canvasElement: HTMLCanvasElement, player: Player) {
  canvas = canvasElement;
  ctx = canvas.getContext('2d');

  // Включаем High-Quality Rendering
  if (ctx) {
      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';
  }

  generateTextures();
  generateWorld(player.x, player.y);
}

/**
 * Генерация мира
 */
function generateWorld(playerX: number, playerY: number) {
    world = {}; 
    const playerTileX = Math.floor(playerX / TILE_SIZE);
    const playerTileY = Math.floor(playerY / TILE_SIZE);

    const WORLD_RADIUS = 60; 
    for (let x = playerTileX - WORLD_RADIUS; x < playerTileX + WORLD_RADIUS; x++) {
        for (let y = playerTileY - WORLD_RADIUS; y < playerTileY + WORLD_RADIUS; y++) {
            const key = `${x},${y}`;
            const dist = Math.sqrt(Math.pow(playerTileX - x, 2) + Math.pow(playerTileY - y, 2));

            if (dist < 4) {
                world[key] = 'grass';
                continue;
            }

            // Шум Перлина (упрощенный) для биомов
            const noise = Math.sin(x * 0.1) * Math.cos(y * 0.1) + Math.random() * 0.1;

            if (noise > 0.65) {
                world[key] = 'water';
            } else if (noise > 0.3 && Math.random() < 0.2) { 
                // Деревья растут группами ("леса")
                world[key] = 'tree';
            } else if (Math.random() < 0.02) {
                world[key] = 'stone';
            } else {
                world[key] = 'grass';
            }
        }
    }
}

export function getTile(tileX: number, tileY: number): TileType {
    return world[`${Math.floor(tileX)},${Math.floor(tileY)}`] || 'grass';
}

export function destroyTile(tileX: number, tileY: number) {
    world[`${tileX},${tileY}`] = 'grass';
}

export function canMoveTo(x: number, y: number, width: number, height: number): boolean {
    const padding = 15; 
    const checkWidth = width - padding;
    const checkHeight = height - padding;

    // Проверка углов хитбокса
    const corners = [
        { x: x - checkWidth / 2, y: y - checkHeight / 2 + 10 }, // Чуть ниже, чтобы ноги были "в мире"
        { x: x + checkWidth / 2, y: y - checkHeight / 2 + 10 },
        { x: x - checkWidth / 2, y: y + checkHeight / 2 }, 
        { x: x + checkWidth / 2, y: y + checkHeight / 2 }, 
    ];

    for (const corner of corners) {
        const tileX = Math.floor(corner.x / TILE_SIZE);
        const tileY = Math.floor(corner.y / TILE_SIZE);
        const tileType = getTile(tileX, tileY);
        // Вода блокирует, деревья и камни блокируют
        if (tileType === 'tree' || tileType === 'stone' || tileType === 'water') {
            return false;
        }
    }
    return true;
}

// --- ОТРИСОВКА ИГРОКА (HERO STYLE) ---

function drawPlayer(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean) {
    const x = player.x;
    const y = player.y;

    // Тень под персонажем
    ctx.fillStyle = 'rgba(0,0,0,0.3)';
    ctx.beginPath();
    ctx.ellipse(x, y + 12, 12, 5, 0, 0, Math.PI*2);
    ctx.fill();

    // Плащ/Накидка (Сзади)
    ctx.fillStyle = isLocal ? '#D32F2F' : '#5D4037'; // Красный плащ для себя
    ctx.beginPath();
    ctx.moveTo(x - 8, y - 5);
    ctx.lineTo(x + 8, y - 5);
    ctx.lineTo(x + 10, y + 10);
    ctx.lineTo(x - 10, y + 10);
    ctx.fill();

    // Тело (Броня)
    ctx.fillStyle = player.color; // Основной цвет (Броня)
    ctx.beginPath();
    ctx.roundRect(x - 9, y - 10, 18, 18, 5);
    ctx.fill();

    // Деталь брони (блик)
    ctx.fillStyle = 'rgba(255,255,255,0.2)';
    ctx.fillRect(x - 9, y - 10, 18, 8);

    // Голова (Шлем)
    ctx.fillStyle = '#CFD8DC'; // Серебристый
    ctx.beginPath();
    ctx.arc(x, y - 16, 9, 0, Math.PI*2);
    ctx.fill();

    // Прорезь шлема
    ctx.fillStyle = '#263238';
    ctx.fillRect(x - 4, y - 18, 8, 3);
    ctx.fillRect(x - 1, y - 18, 2, 8);

    // Оружие (Меч в руке)
    ctx.save();
    ctx.translate(x + 12, y);
    ctx.rotate(Math.PI / 4); // Наклон меча

    // Лезвие
    ctx.fillStyle = '#E0E0E0';
    ctx.fillRect(0, -12, 4, 16);
    // Рукоять
    ctx.fillStyle = '#5D4037';
    ctx.fillRect(0, 4, 4, 6);
    // Гарда
    ctx.fillStyle = '#FFD700';
    ctx.fillRect(-3, 2, 10, 2);

    ctx.restore();

    // Никнейм
    if (!isLocal) {
        ctx.fillStyle = '#FFFFFF';
        ctx.shadowColor = 'black';
        ctx.shadowBlur = 4;
        ctx.font = 'bold 12px "Segoe UI", sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(player.nickname, x, y - 35);
        ctx.shadowBlur = 0;
    }
}

interface RenderObject {
    y: number; // Z-index для сортировки (глубина)
    type: 'tree' | 'stone' | 'player';
    data: any;
}

export function renderGame(players: Players, myId: string) {
  if (!ctx || !canvas) return;
  const me = players[myId];
  if (!me) return;

  // Заливаем фон базовым цветом земли
  ctx.fillStyle = '#4e8c33'; 
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // Камера центрируется на игроке
  const cameraX = Math.floor(me.x - canvas.width / 2);
  const cameraY = Math.floor(me.y - canvas.height / 2);

  ctx.save();
  ctx.translate(-cameraX, -cameraY);

  // Определяем границы видимости (culling)
  const startTileX = Math.floor(cameraX / TILE_SIZE) - 1;
  const endTileX = startTileX + Math.ceil(canvas.width / TILE_SIZE) + 2;
  const startTileY = Math.floor(cameraY / TILE_SIZE) - 2; // Берем запас сверху для высоких деревьев
  const endTileY = startTileY + Math.ceil(canvas.height / TILE_SIZE) + 4;

  const renderList: RenderObject[] = [];

  // 1. СЛОЙ ЗЕМЛИ (Рисуем сразу, без сортировки)
  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const type = getTile(x, y);
        const screenX = x * TILE_SIZE;
        const screenY = y * TILE_SIZE;

        if (type === 'water') {
            ctx.drawImage(textures['water'], screenX, screenY);
        } else {
            // Трава везде как подложка
            ctx.drawImage(textures['grass'], screenX, screenY);
        }

        // Подготовка объектов для сортировки
        if (type === 'tree') {
            // Дерево 140x220. Центр текстуры по X (70) должен совпасть с центром тайла (20). Смещение: -50.
            // Основание дерева (220-15) должно быть внизу тайла.
            renderList.push({ 
                y: screenY + TILE_SIZE, // Сортируем по низу тайла
                type: 'tree', 
                data: { x: screenX - 50, y: screenY - 180 } // Рисуем сильно выше
            });
        } else if (type === 'stone') {
            renderList.push({ 
                y: screenY + TILE_SIZE, 
                type: 'stone', 
                data: { x: screenX, y: screenY } 
            });
        }
    }
  }

  // 2. ИГРОКИ
  for (const id in players) {
      const p = players[id];
      renderList.push({ y: p.y, type: 'player', data: { player: p, isLocal: id === myId } });
  }

  // 3. СОРТИРОВКА ПО ГЛУБИНЕ (Самое важное для RPG вида)
  renderList.sort((a, b) => a.y - b.y);

  // 4. ОТРИСОВКА ОБЪЕКТОВ
  for (const obj of renderList) {
      if (obj.type === 'tree') {
          ctx.drawImage(textures['tree'], obj.data.x, obj.data.y);
      } else if (obj.type === 'stone') {
          ctx.drawImage(textures['stone'], obj.data.x, obj.data.y);
      } else if (obj.type === 'player') {
          drawPlayer(ctx, obj.data.player, obj.data.isLocal);
      }
  }

  // (Optional) Vignette effect для атмосферы
  ctx.restore(); // Возвращаемся к координатам экрана

  // Легкая виньетка поверх экрана
  const grad = ctx.createRadialGradient(canvas.width/2, canvas.height/2, canvas.height/3, canvas.width/2, canvas.height/2, canvas.height);
  grad.addColorStop(0, 'rgba(0,0,0,0)');
  grad.addColorStop(1, 'rgba(0,0,0,0.3)');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, canvas.width, canvas.height);
}

// game.ts: Управляет отрисовкой игрового мира в стиле Modern Stylized RPG (2025 Vision).
import { Player, Players, WorldMap, TileType } from './types';

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;

export const TILE_SIZE = 40;
let world: WorldMap = {};

// Кэш текстур
const textures: Record<string, HTMLCanvasElement> = {};

// --- ГЕНЕРАЦИЯ ТЕКСТУР (High Fidelity) ---

function generateTextures() {
    // 1. Трава (Clean & Uniform)
    const grassC = document.createElement('canvas');
    grassC.width = TILE_SIZE;
    grassC.height = TILE_SIZE;
    const gCtx = grassC.getContext('2d')!;

    // Ровный цвет базы (без градиентов) - приятный RPG зеленый
    gCtx.fillStyle = '#4e8c33'; 
    gCtx.fillRect(0, 0, TILE_SIZE, TILE_SIZE);

    // Случайные травинки
    // Рисуем их простыми штрихами, чтобы не перегружать картинку
    const bladeCount = 6; // Количество травинок на тайл

    for(let i=0; i<bladeCount; i++) {
        const x = Math.random() * (TILE_SIZE - 4);
        const y = Math.random() * (TILE_SIZE - 6) + 3;
        const h = 3 + Math.random() * 3; // Высота от 3 до 6 пикселей

        // Травинка (Светлее фона)
        gCtx.fillStyle = '#6ab04c'; 
        gCtx.beginPath();
        gCtx.moveTo(x, y);
        gCtx.lineTo(x + 1, y - h); // Верхушка
        gCtx.lineTo(x + 2, y);
        gCtx.fill();
    }

    textures['grass'] = grassC;

    // 2. Вода (Deep & Reflective)
    const waterC = document.createElement('canvas');
    waterC.width = TILE_SIZE;
    waterC.height = TILE_SIZE;
    const wCtx = waterC.getContext('2d')!;

    // Глубокий океанический градиент
    const waterGrad = wCtx.createRadialGradient(TILE_SIZE/2, TILE_SIZE/2, 0, TILE_SIZE/2, TILE_SIZE/2, TILE_SIZE);
    waterGrad.addColorStop(0, '#4FA4F4'); // Светлее в центре
    waterGrad.addColorStop(1, '#2979FF'); // Глубокий синий
    wCtx.fillStyle = waterGrad;
    wCtx.fillRect(0, 0, TILE_SIZE, TILE_SIZE);

    // Волны (Гладкие линии)
    wCtx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
    wCtx.lineWidth = 1.5;
    wCtx.beginPath();
    wCtx.moveTo(5, 10);
    wCtx.quadraticCurveTo(15, 5, 25, 10);
    wCtx.stroke();

    wCtx.beginPath();
    wCtx.moveTo(15, 30);
    wCtx.quadraticCurveTo(25, 25, 35, 30);
    wCtx.stroke();

    textures['water'] = waterC;

    // 3. Камень (Realistic Rock)
    const stoneC = document.createElement('canvas');
    stoneC.width = TILE_SIZE;
    stoneC.height = TILE_SIZE;
    const sCtx = stoneC.getContext('2d')!;

    const cx = TILE_SIZE / 2;
    const cy = TILE_SIZE / 2 + 5;

    // Тень
    sCtx.fillStyle = 'rgba(0,0,0,0.3)';
    sCtx.beginPath();
    sCtx.ellipse(cx, cy + 10, 15, 6, 0, 0, Math.PI*2);
    sCtx.fill();

    // Форма камня (Сложная)
    sCtx.beginPath();
    sCtx.moveTo(cx - 15, cy + 5);
    sCtx.lineTo(cx - 10, cy - 10); // Left sharp edge
    sCtx.lineTo(cx, cy - 15);      // Top peak
    sCtx.lineTo(cx + 12, cy - 8);  // Right shoulder
    sCtx.lineTo(cx + 15, cy + 5);  // Right base
    sCtx.lineTo(cx, cy + 10);      // Bottom
    sCtx.closePath();

    // Градиентная заливка
    const rockGrad = sCtx.createLinearGradient(0, 0, TILE_SIZE, TILE_SIZE);
    rockGrad.addColorStop(0, '#90A4AE'); // Light Blue Grey
    rockGrad.addColorStop(1, '#546E7A'); // Dark Blue Grey
    sCtx.fillStyle = rockGrad;
    sCtx.fill();

    // Хайлайты (Трещины/Грани)
    sCtx.fillStyle = 'rgba(255,255,255,0.3)';
    sCtx.beginPath();
    sCtx.moveTo(cx - 10, cy - 10);
    sCtx.lineTo(cx, cy - 15);
    sCtx.lineTo(cx + 5, cy - 5);
    sCtx.fill();

    textures['stone'] = stoneC;

    // 4. ДЕРЕВО (HIGH FANTASY STYLE)
    // Огромное, высокое, детализированное
    const treeW = 140; 
    const treeH = 220; // Очень высокое!
    const treeC = document.createElement('canvas');
    treeC.width = treeW; 
    treeC.height = treeH; 
    const tCtx = treeC.getContext('2d')!;

    const tX = treeW / 2;
    const tBaseY = treeH - 15;

    // Тень от всего дерева
    tCtx.fillStyle = 'rgba(0,0,0,0.25)';
    tCtx.filter = 'blur(6px)';
    tCtx.beginPath();
    tCtx.ellipse(tX, tBaseY - 5, 30, 10, 0, 0, Math.PI*2);
    tCtx.fill();
    tCtx.filter = 'none';

    // Ствол (Реалистичный, темный)
    const trunkGrad = tCtx.createLinearGradient(tX - 15, 0, tX + 15, 0);
    trunkGrad.addColorStop(0, '#3E2723'); // Shadow side
    trunkGrad.addColorStop(0.4, '#5D4037'); // Highlight
    trunkGrad.addColorStop(1, '#251714'); // Dark side

    tCtx.fillStyle = trunkGrad;
    tCtx.beginPath();
    // Корни
    tCtx.moveTo(tX - 15, tBaseY); 
    tCtx.quadraticCurveTo(tX - 10, tBaseY - 30, tX - 10, tBaseY - 80); // Left side
    tCtx.lineTo(tX + 10, tBaseY - 80);
    tCtx.quadraticCurveTo(tX + 10, tBaseY - 30, tX + 15, tBaseY); // Right side
    tCtx.fill();

    // КРОНА (Procedural Fluffy Leaves)
    // Рисуем сотню маленьких кружочков, чтобы создать эффект листвы
    const canopyCenterY = tBaseY - 140;

    // Функция рисования пучка листвы
    const drawLeafClump = (lx: number, ly: number, size: number, colorBase: string, colorLight: string) => {
        const grad = tCtx.createRadialGradient(lx - size/3, ly - size/3, size/4, lx, ly, size);
        grad.addColorStop(0, colorLight);
        grad.addColorStop(1, colorBase);
        tCtx.fillStyle = grad;
        tCtx.beginPath();
        tCtx.arc(lx, ly, size, 0, Math.PI*2);
        tCtx.fill();
    };

    // Массив позиций для кроны (формируем форму гриба/дерева)
    const layers = [
        { y: 60, w: 50, count: 12, s: 20, c: '#1B5E20', l: '#2E7D32' }, // Bottom Darkest Layer
        { y: 30, w: 55, count: 14, s: 22, c: '#2E7D32', l: '#43A047' }, // Mid Layer
        { y: 0, w: 45, count: 12, s: 24, c: '#43A047', l: '#66BB6A' },  // Upper Layer
        { y: -30, w: 30, count: 8, s: 22, c: '#66BB6A', l: '#A5D6A7' }  // Top Highlights
    ];

    layers.forEach(layer => {
        for(let i=0; i<layer.count; i++) {
            // Случайное смещение внутри слоя
            const offsetX = (Math.random() - 0.5) * layer.w * 2;
            const offsetY = (Math.random() - 0.5) * 20;

            drawLeafClump(
                tX + offsetX, 
                canopyCenterY + layer.y + offsetY, 
                layer.s + Math.random()*5, 
                layer.c, 
                layer.l
            );
        }
    });

    textures['tree'] = treeC;
}

/**
 * Инициализация
 */
export function init(canvasElement: HTMLCanvasElement, player: Player) {
  canvas = canvasElement;
  ctx = canvas.getContext('2d');

  // Включаем High-Quality Rendering
  if (ctx) {
      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';
  }

  generateTextures();
  generateWorld(player.x, player.y);
}

/**
 * Генерация мира
 */
function generateWorld(playerX: number, playerY: number) {
    world = {}; 
    const playerTileX = Math.floor(playerX / TILE_SIZE);
    const playerTileY = Math.floor(playerY / TILE_SIZE);

    const WORLD_RADIUS = 60; 
    for (let x = playerTileX - WORLD_RADIUS; x < playerTileX + WORLD_RADIUS; x++) {
        for (let y = playerTileY - WORLD_RADIUS; y < playerTileY + WORLD_RADIUS; y++) {
            const key = `${x},${y}`;
            const dist = Math.sqrt(Math.pow(playerTileX - x, 2) + Math.pow(playerTileY - y, 2));

            if (dist < 4) {
                world[key] = 'grass';
                continue;
            }

            // Шум Перлина (упрощенный) для биомов
            const noise = Math.sin(x * 0.1) * Math.cos(y * 0.1) + Math.random() * 0.1;

            if (noise > 0.65) {
                world[key] = 'water';
            } else if (noise > 0.3 && Math.random() < 0.2) { 
                // Деревья растут группами ("леса")
                world[key] = 'tree';
            } else if (Math.random() < 0.02) {
                world[key] = 'stone';
            } else {
                world[key] = 'grass';
            }
        }
    }
}

export function getTile(tileX: number, tileY: number): TileType {
    return world[`${Math.floor(tileX)},${Math.floor(tileY)}`] || 'grass';
}

export function destroyTile(tileX: number, tileY: number) {
    world[`${tileX},${tileY}`] = 'grass';
}

export function canMoveTo(x: number, y: number, width: number, height: number): boolean {
    const padding = 15; 
    const checkWidth = width - padding;
    const checkHeight = height - padding;

    // Проверка углов хитбокса
    const corners = [
        { x: x - checkWidth / 2, y: y - checkHeight / 2 + 10 }, // Чуть ниже, чтобы ноги были "в мире"
        { x: x + checkWidth / 2, y: y - checkHeight / 2 + 10 },
        { x: x - checkWidth / 2, y: y + checkHeight / 2 }, 
        { x: x + checkWidth / 2, y: y + checkHeight / 2 }, 
    ];

    for (const corner of corners) {
        const tileX = Math.floor(corner.x / TILE_SIZE);
        const tileY = Math.floor(corner.y / TILE_SIZE);
        const tileType = getTile(tileX, tileY);
        // Вода блокирует, деревья и камни блокируют
        if (tileType === 'tree' || tileType === 'stone' || tileType === 'water') {
            return false;
        }
    }
    return true;
}

// --- ОТРИСОВКА ИГРОКА (HERO STYLE) ---

function drawPlayer(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean) {
    const x = player.x;
    const y = player.y;

    // Тень под персонажем
    ctx.fillStyle = 'rgba(0,0,0,0.3)';
    ctx.beginPath();
    ctx.ellipse(x, y + 12, 12, 5, 0, 0, Math.PI*2);
    ctx.fill();

    // Плащ/Накидка (Сзади)
    ctx.fillStyle = isLocal ? '#D32F2F' : '#5D4037'; // Красный плащ для себя
    ctx.beginPath();
    ctx.moveTo(x - 8, y - 5);
    ctx.lineTo(x + 8, y - 5);
    ctx.lineTo(x + 10, y + 10);
    ctx.lineTo(x - 10, y + 10);
    ctx.fill();

    // Тело (Броня)
    ctx.fillStyle = player.color; // Основной цвет (Броня)
    ctx.beginPath();
    ctx.roundRect(x - 9, y - 10, 18, 18, 5);
    ctx.fill();

    // Деталь брони (блик)
    ctx.fillStyle = 'rgba(255,255,255,0.2)';
    ctx.fillRect(x - 9, y - 10, 18, 8);

    // Голова (Шлем)
    ctx.fillStyle = '#CFD8DC'; // Серебристый
    ctx.beginPath();
    ctx.arc(x, y - 16, 9, 0, Math.PI*2);
    ctx.fill();

    // Прорезь шлема
    ctx.fillStyle = '#263238';
    ctx.fillRect(x - 4, y - 18, 8, 3);
    ctx.fillRect(x - 1, y - 18, 2, 8);

    // Оружие (Меч в руке)
    ctx.save();
    ctx.translate(x + 12, y);
    ctx.rotate(Math.PI / 4); // Наклон меча

    // Лезвие
    ctx.fillStyle = '#E0E0E0';
    ctx.fillRect(0, -12, 4, 16);
    // Рукоять
    ctx.fillStyle = '#5D4037';
    ctx.fillRect(0, 4, 4, 6);
    // Гарда
    ctx.fillStyle = '#FFD700';
    ctx.fillRect(-3, 2, 10, 2);

    ctx.restore();

    // Никнейм
    if (!isLocal) {
        ctx.fillStyle = '#FFFFFF';
        ctx.shadowColor = 'black';
        ctx.shadowBlur = 4;
        ctx.font = 'bold 12px "Segoe UI", sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(player.nickname, x, y - 35);
        ctx.shadowBlur = 0;
    }
}

interface RenderObject {
    y: number; // Z-index для сортировки (глубина)
    type: 'tree' | 'stone' | 'player';
    data: any;
}

export function renderGame(players: Players, myId: string) {
  if (!ctx || !canvas) return;
  const me = players[myId];
  if (!me) return;

  // Заливаем фон базовым цветом земли
  ctx.fillStyle = '#4e8c33'; 
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // Камера центрируется на игроке
  const cameraX = Math.floor(me.x - canvas.width / 2);
  const cameraY = Math.floor(me.y - canvas.height / 2);

  ctx.save();
  ctx.translate(-cameraX, -cameraY);

  // Определяем границы видимости (culling)
  const startTileX = Math.floor(cameraX / TILE_SIZE) - 1;
  const endTileX = startTileX + Math.ceil(canvas.width / TILE_SIZE) + 2;
  const startTileY = Math.floor(cameraY / TILE_SIZE) - 2; // Берем запас сверху для высоких деревьев
  const endTileY = startTileY + Math.ceil(canvas.height / TILE_SIZE) + 4;

  const renderList: RenderObject[] = [];

  // 1. СЛОЙ ЗЕМЛИ (Рисуем сразу, без сортировки)
  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const type = getTile(x, y);
        const screenX = x * TILE_SIZE;
        const screenY = y * TILE_SIZE;

        if (type === 'water') {
            ctx.drawImage(textures['water'], screenX, screenY);
        } else {
            // Трава везде как подложка
            ctx.drawImage(textures['grass'], screenX, screenY);
        }

        // Подготовка объектов для сортировки
        if (type === 'tree') {
            // Дерево 140x220. Центр текстуры по X (70) должен совпасть с центром тайла (20). Смещение: -50.
            // Основание дерева (220-15) должно быть внизу тайла.
            renderList.push({ 
                y: screenY + TILE_SIZE, // Сортируем по низу тайла
                type: 'tree', 
                data: { x: screenX - 50, y: screenY - 180 } // Рисуем сильно выше
            });
        } else if (type === 'stone') {
            renderList.push({ 
                y: screenY + TILE_SIZE, 
                type: 'stone', 
                data: { x: screenX, y: screenY } 
            });
        }
    }
  }

  // 2. ИГРОКИ
  for (const id in players) {
      const p = players[id];
      renderList.push({ y: p.y, type: 'player', data: { player: p, isLocal: id === myId } });
  }

  // 3. СОРТИРОВКА ПО ГЛУБИНЕ (Самое важное для RPG вида)
  renderList.sort((a, b) => a.y - b.y);

  // 4. ОТРИСОВКА ОБЪЕКТОВ
  for (const obj of renderList) {
      if (obj.type === 'tree') {
          // ЛОГИКА ПРОЗРАЧНОСТИ
          // Центр спрайта дерева по X = obj.data.x + 70 (половина ширины 140)
          // Основание ствола дерева по Y = obj.data.y + 200 (примерно низ спрайта)
          const treeCenterX = obj.data.x + 70;
          const treeBaseY = obj.data.y + 200;

          const dist = Math.sqrt(Math.pow(me.x - treeCenterX, 2) + Math.pow(me.y - treeBaseY, 2));

          // Если игрок ближе чем 150 пикселей, дерево становится прозрачным
          // Чем ближе, тем прозрачнее (минимум 0.4)
          let alpha = 1.0;
          if (dist < 150) {
            alpha = Math.max(0.4, dist / 150);
          }

          ctx.globalAlpha = alpha;
          ctx.drawImage(textures['tree'], obj.data.x, obj.data.y);
          ctx.globalAlpha = 1.0; // Сброс прозрачности

      } else if (obj.type === 'stone') {
          ctx.drawImage(textures['stone'], obj.data.x, obj.data.y);
      } else if (obj.type === 'player') {
          drawPlayer(ctx, obj.data.player, obj.data.isLocal);
      }
  }

  // (Optional) Vignette effect для атмосферы
  ctx.restore(); // Возвращаемся к координатам экрана

  // Легкая виньетка поверх экрана
  const grad = ctx.createRadialGradient(canvas.width/2, canvas.height/2, canvas.height/3, canvas.width/2, canvas.height/2, canvas.height);
  grad.addColorStop(0, 'rgba(0,0,0,0)');
  grad.addColorStop(1, 'rgba(0,0,0,0.3)');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, canvas.width, canvas.height);
}

// game.ts: Управляет отрисовкой игрового мира в стиле Modern Stylized RPG (2025 Vision).
import { Player, Players, WorldMap, TileType } from './types';

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;

export const TILE_SIZE = 40;
let world: WorldMap = {};

// Кэш текстур
const textures: Record<string, HTMLCanvasElement> = {};

// --- ГЕНЕРАЦИЯ ТЕКСТУР (High Fidelity) ---

function generateTextures() {
    // 1. Трава (Clean & Uniform)
    const grassC = document.createElement('canvas');
    grassC.width = TILE_SIZE;
    grassC.height = TILE_SIZE;
    const gCtx = grassC.getContext('2d')!;

    // Ровный цвет базы (без градиентов) - приятный RPG зеленый
    gCtx.fillStyle = '#4e8c33'; 
    gCtx.fillRect(0, 0, TILE_SIZE, TILE_SIZE);

    // Случайные травинки
    // Рисуем их простыми штрихами, чтобы не перегружать картинку
    const bladeCount = 6; // Количество травинок на тайл

    for(let i=0; i<bladeCount; i++) {
        const x = Math.random() * (TILE_SIZE - 4);
        const y = Math.random() * (TILE_SIZE - 6) + 3;
        const h = 3 + Math.random() * 3; // Высота от 3 до 6 пикселей

        // Травинка (Светлее фона)
        gCtx.fillStyle = '#6ab04c'; 
        gCtx.beginPath();
        gCtx.moveTo(x, y);
        gCtx.lineTo(x + 1, y - h); // Верхушка
        gCtx.lineTo(x + 2, y);
        gCtx.fill();
    }

    textures['grass'] = grassC;

    // 2. Вода (Deep & Reflective)
    const waterC = document.createElement('canvas');
    waterC.width = TILE_SIZE;
    waterC.height = TILE_SIZE;
    const wCtx = waterC.getContext('2d')!;

    // Глубокий океанический градиент
    const waterGrad = wCtx.createRadialGradient(TILE_SIZE/2, TILE_SIZE/2, 0, TILE_SIZE/2, TILE_SIZE/2, TILE_SIZE);
    waterGrad.addColorStop(0, '#4FA4F4'); // Светлее в центре
    waterGrad.addColorStop(1, '#2979FF'); // Глубокий синий
    wCtx.fillStyle = waterGrad;
    wCtx.fillRect(0, 0, TILE_SIZE, TILE_SIZE);

    // Волны (Гладкие линии)
    wCtx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
    wCtx.lineWidth = 1.5;
    wCtx.beginPath();
    wCtx.moveTo(5, 10);
    wCtx.quadraticCurveTo(15, 5, 25, 10);
    wCtx.stroke();

    wCtx.beginPath();
    wCtx.moveTo(15, 30);
    wCtx.quadraticCurveTo(25, 25, 35, 30);
    wCtx.stroke();

    textures['water'] = waterC;

    // 3. Камень (Realistic Rock)
    const stoneC = document.createElement('canvas');
    stoneC.width = TILE_SIZE;
    stoneC.height = TILE_SIZE;
    const sCtx = stoneC.getContext('2d')!;

    const cx = TILE_SIZE / 2;
    const cy = TILE_SIZE / 2 + 5;

    // Тень
    sCtx.fillStyle = 'rgba(0,0,0,0.3)';
    sCtx.beginPath();
    sCtx.ellipse(cx, cy + 10, 15, 6, 0, 0, Math.PI*2);
    sCtx.fill();

    // Форма камня (Сложная)
    sCtx.beginPath();
    sCtx.moveTo(cx - 15, cy + 5);
    sCtx.lineTo(cx - 10, cy - 10); // Left sharp edge
    sCtx.lineTo(cx, cy - 15);      // Top peak
    sCtx.lineTo(cx + 12, cy - 8);  // Right shoulder
    sCtx.lineTo(cx + 15, cy + 5);  // Right base
    sCtx.lineTo(cx, cy + 10);      // Bottom
    sCtx.closePath();

    // Градиентная заливка
    const rockGrad = sCtx.createLinearGradient(0, 0, TILE_SIZE, TILE_SIZE);
    rockGrad.addColorStop(0, '#90A4AE'); // Light Blue Grey
    rockGrad.addColorStop(1, '#546E7A'); // Dark Blue Grey
    sCtx.fillStyle = rockGrad;
    sCtx.fill();

    // Хайлайты (Трещины/Грани)
    sCtx.fillStyle = 'rgba(255,255,255,0.3)';
    sCtx.beginPath();
    sCtx.moveTo(cx - 10, cy - 10);
    sCtx.lineTo(cx, cy - 15);
    sCtx.lineTo(cx + 5, cy - 5);
    sCtx.fill();

    textures['stone'] = stoneC;

    // 4. ДЕРЕВО (HIGH FANTASY STYLE)
    // Огромное, высокое, детализированное
    const treeW = 140; 
    const treeH = 220; // Очень высокое!
    const treeC = document.createElement('canvas');
    treeC.width = treeW; 
    treeC.height = treeH; 
    const tCtx = treeC.getContext('2d')!;

    const tX = treeW / 2;
    const tBaseY = treeH - 15;

    // Тень от всего дерева
    tCtx.fillStyle = 'rgba(0,0,0,0.25)';
    tCtx.filter = 'blur(6px)';
    tCtx.beginPath();
    tCtx.ellipse(tX, tBaseY - 5, 30, 10, 0, 0, Math.PI*2);
    tCtx.fill();
    tCtx.filter = 'none';

    // Ствол (Реалистичный, темный)
    const trunkGrad = tCtx.createLinearGradient(tX - 15, 0, tX + 15, 0);
    trunkGrad.addColorStop(0, '#3E2723'); // Shadow side
    trunkGrad.addColorStop(0.4, '#5D4037'); // Highlight
    trunkGrad.addColorStop(1, '#251714'); // Dark side

    tCtx.fillStyle = trunkGrad;
    tCtx.beginPath();
    // Корни
    tCtx.moveTo(tX - 15, tBaseY); 
    tCtx.quadraticCurveTo(tX - 10, tBaseY - 30, tX - 10, tBaseY - 80); // Left side
    tCtx.lineTo(tX + 10, tBaseY - 80);
    tCtx.quadraticCurveTo(tX + 10, tBaseY - 30, tX + 15, tBaseY); // Right side
    tCtx.fill();

    // КРОНА (Procedural Fluffy Leaves)
    // Рисуем сотню маленьких кружочков, чтобы создать эффект листвы
    const canopyCenterY = tBaseY - 140;

    // Функция рисования пучка листвы
    const drawLeafClump = (lx: number, ly: number, size: number, colorBase: string, colorLight: string) => {
        const grad = tCtx.createRadialGradient(lx - size/3, ly - size/3, size/4, lx, ly, size);
        grad.addColorStop(0, colorLight);
        grad.addColorStop(1, colorBase);
        tCtx.fillStyle = grad;
        tCtx.beginPath();
        tCtx.arc(lx, ly, size, 0, Math.PI*2);
        tCtx.fill();
    };

    // Массив позиций для кроны (формируем форму гриба/дерева)
    const layers = [
        { y: 60, w: 50, count: 12, s: 20, c: '#1B5E20', l: '#2E7D32' }, // Bottom Darkest Layer
        { y: 30, w: 55, count: 14, s: 22, c: '#2E7D32', l: '#43A047' }, // Mid Layer
        { y: 0, w: 45, count: 12, s: 24, c: '#43A047', l: '#66BB6A' },  // Upper Layer
        { y: -30, w: 30, count: 8, s: 22, c: '#66BB6A', l: '#A5D6A7' }  // Top Highlights
    ];

    layers.forEach(layer => {
        for(let i=0; i<layer.count; i++) {
            // Случайное смещение внутри слоя
            const offsetX = (Math.random() - 0.5) * layer.w * 2;
            const offsetY = (Math.random() - 0.5) * 20;

            drawLeafClump(
                tX + offsetX, 
                canopyCenterY + layer.y + offsetY, 
                layer.s + Math.random()*5, 
                layer.c, 
                layer.l
            );
        }
    });

    textures['tree'] = treeC;
}

/**
 * Инициализация
 */
export function init(canvasElement: HTMLCanvasElement, player: Player) {
  canvas = canvasElement;
  ctx = canvas.getContext('2d');

  // Включаем High-Quality Rendering
  if (ctx) {
      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';
  }

  generateTextures();
  generateWorld(player.x, player.y);
}

/**
 * Генерация мира
 */
function generateWorld(playerX: number, playerY: number) {
    world = {}; 
    const playerTileX = Math.floor(playerX / TILE_SIZE);
    const playerTileY = Math.floor(playerY / TILE_SIZE);

    const WORLD_RADIUS = 60; 
    for (let x = playerTileX - WORLD_RADIUS; x < playerTileX + WORLD_RADIUS; x++) {
        for (let y = playerTileY - WORLD_RADIUS; y < playerTileY + WORLD_RADIUS; y++) {
            const key = `${x},${y}`;
            const dist = Math.sqrt(Math.pow(playerTileX - x, 2) + Math.pow(playerTileY - y, 2));

            if (dist < 4) {
                world[key] = 'grass';
                continue;
            }

            // Шум Перлина (упрощенный) для биомов
            const noise = Math.sin(x * 0.1) * Math.cos(y * 0.1) + Math.random() * 0.1;

            if (noise > 0.65) {
                world[key] = 'water';
            } else if (noise > 0.3 && Math.random() < 0.2) { 
                // Деревья растут группами ("леса")
                world[key] = 'tree';
            } else if (Math.random() < 0.02) {
                world[key] = 'stone';
            } else {
                world[key] = 'grass';
            }
        }
    }
}

export function getTile(tileX: number, tileY: number): TileType {
    return world[`${Math.floor(tileX)},${Math.floor(tileY)}`] || 'grass';
}

export function destroyTile(tileX: number, tileY: number) {
    world[`${tileX},${tileY}`] = 'grass';
}

export function canMoveTo(x: number, y: number, width: number, height: number): boolean {
    const padding = 15; 
    const checkWidth = width - padding;
    const checkHeight = height - padding;

    // Проверка углов хитбокса
    const corners = [
        { x: x - checkWidth / 2, y: y - checkHeight / 2 + 10 }, // Чуть ниже, чтобы ноги были "в мире"
        { x: x + checkWidth / 2, y: y - checkHeight / 2 + 10 },
        { x: x - checkWidth / 2, y: y + checkHeight / 2 }, 
        { x: x + checkWidth / 2, y: y + checkHeight / 2 }, 
    ];

    for (const corner of corners) {
        const tileX = Math.floor(corner.x / TILE_SIZE);
        const tileY = Math.floor(corner.y / TILE_SIZE);
        const tileType = getTile(tileX, tileY);
        // Вода блокирует, деревья и камни блокируют
        if (tileType === 'tree' || tileType === 'stone' || tileType === 'water') {
            return false;
        }
    }
    return true;
}

// --- ОТРИСОВКА ИГРОКА (HERO STYLE) ---

function drawPlayer(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean) {
    const x = player.x;
    const y = player.y;

    // Тень под персонажем
    ctx.fillStyle = 'rgba(0,0,0,0.3)';
    ctx.beginPath();
    ctx.ellipse(x, y + 12, 12, 5, 0, 0, Math.PI*2);
    ctx.fill();

    // Плащ/Накидка (Сзади)
    ctx.fillStyle = isLocal ? '#D32F2F' : '#5D4037'; // Красный плащ для себя
    ctx.beginPath();
    ctx.moveTo(x - 8, y - 5);
    ctx.lineTo(x + 8, y - 5);
    ctx.lineTo(x + 10, y + 10);
    ctx.lineTo(x - 10, y + 10);
    ctx.fill();

    // Тело (Броня)
    ctx.fillStyle = player.color; // Основной цвет (Броня)
    ctx.beginPath();
    ctx.roundRect(x - 9, y - 10, 18, 18, 5);
    ctx.fill();

    // Деталь брони (блик)
    ctx.fillStyle = 'rgba(255,255,255,0.2)';
    ctx.fillRect(x - 9, y - 10, 18, 8);

    // Голова (Шлем)
    ctx.fillStyle = '#CFD8DC'; // Серебристый
    ctx.beginPath();
    ctx.arc(x, y - 16, 9, 0, Math.PI*2);
    ctx.fill();

    // Прорезь шлема
    ctx.fillStyle = '#263238';
    ctx.fillRect(x - 4, y - 18, 8, 3);
    ctx.fillRect(x - 1, y - 18, 2, 8);

    // Оружие (Меч в руке)
    ctx.save();
    ctx.translate(x + 12, y);
    ctx.rotate(Math.PI / 4); // Наклон меча

    // Лезвие
    ctx.fillStyle = '#E0E0E0';
    ctx.fillRect(0, -12, 4, 16);
    // Рукоять
    ctx.fillStyle = '#5D4037';
    ctx.fillRect(0, 4, 4, 6);
    // Гарда
    ctx.fillStyle = '#FFD700';
    ctx.fillRect(-3, 2, 10, 2);

    ctx.restore();

    // Никнейм
    if (!isLocal) {
        ctx.fillStyle = '#FFFFFF';
        ctx.shadowColor = 'black';
        ctx.shadowBlur = 4;
        ctx.font = 'bold 12px "Segoe UI", sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(player.nickname, x, y - 35);
        ctx.shadowBlur = 0;
    }
}

interface RenderObject {
    y: number; // Z-index для сортировки (глубина)
    type: 'tree' | 'stone' | 'player';
    data: any;
}

export function renderGame(players: Players, myId: string) {
  if (!ctx || !canvas) return;
  const me = players[myId];
  if (!me) return;

  // Заливаем фон базовым цветом земли
  ctx.fillStyle = '#4e8c33'; 
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // Камера центрируется на игроке
  const cameraX = Math.floor(me.x - canvas.width / 2);
  const cameraY = Math.floor(me.y - canvas.height / 2);

  ctx.save();
  ctx.translate(-cameraX, -cameraY);

  // Определяем границы видимости (culling)
  const startTileX = Math.floor(cameraX / TILE_SIZE) - 1;
  const endTileX = startTileX + Math.ceil(canvas.width / TILE_SIZE) + 2;
  const startTileY = Math.floor(cameraY / TILE_SIZE) - 2; // Берем запас сверху для высоких деревьев
  const endTileY = startTileY + Math.ceil(canvas.height / TILE_SIZE) + 4;

  const renderList: RenderObject[] = [];

  // 1. СЛОЙ ЗЕМЛИ (Рисуем сразу, без сортировки)
  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const type = getTile(x, y);
        const screenX = x * TILE_SIZE;
        const screenY = y * TILE_SIZE;

        if (type === 'water') {
            ctx.drawImage(textures['water'], screenX, screenY);
        } else {
            // Трава везде как подложка
            ctx.drawImage(textures['grass'], screenX, screenY);
        }

        // Подготовка объектов для сортировки
        if (type === 'tree') {
            // Дерево 140x220. Центр текстуры по X (70) должен совпасть с центром тайла (20). Смещение: -50.
            // Основание дерева (220-15) должно быть внизу тайла.
            renderList.push({ 
                y: screenY + TILE_SIZE, // Сортируем по низу тайла
                type: 'tree', 
                data: { x: screenX - 50, y: screenY - 180 } // Рисуем сильно выше
            });
        } else if (type === 'stone') {
            renderList.push({ 
                y: screenY + TILE_SIZE, 
                type: 'stone', 
                data: { x: screenX, y: screenY } 
            });
        }
    }
  }

  // 2. ИГРОКИ
  for (const id in players) {
      const p = players[id];
      renderList.push({ y: p.y, type: 'player', data: { player: p, isLocal: id === myId } });
  }

  // 3. СОРТИРОВКА ПО ГЛУБИНЕ (Самое важное для RPG вида)
  renderList.sort((a, b) => a.y - b.y);

  // 4. ОТРИСОВКА ОБЪЕКТОВ
  for (const obj of renderList) {
      if (obj.type === 'tree') {
          // ЛОГИКА ПРОЗРАЧНОСТИ
          // Рассчитываем дистанцию до ЦЕНТРА спрайта дерева, а не до корней.
          // Спрайт 140x220. Центр: x+70, y+110.
          const treeCenterX = obj.data.x + 70;
          const treeCenterY = obj.data.y + 110;

          const dist = Math.sqrt(Math.pow(me.x - treeCenterX, 2) + Math.pow(me.y - treeCenterY, 2));

          // Если игрок внутри визуального радиуса дерева (с запасом)
          const transparencyRadius = 130; 

          let alpha = 1.0;
          if (dist < transparencyRadius) {
            // Плавный переход: чем ближе к центру, тем прозрачнее
            alpha = Math.max(0.4, dist / transparencyRadius);
          }

          ctx.globalAlpha = alpha;
          ctx.drawImage(textures['tree'], obj.data.x, obj.data.y);
          ctx.globalAlpha = 1.0; // Сброс прозрачности

      } else if (obj.type === 'stone') {
          ctx.drawImage(textures['stone'], obj.data.x, obj.data.y);
      } else if (obj.type === 'player') {
          drawPlayer(ctx, obj.data.player, obj.data.isLocal);
      }
  }

  // (Optional) Vignette effect для атмосферы
  ctx.restore(); // Возвращаемся к координатам экрана

  // Легкая виньетка поверх экрана
  const grad = ctx.createRadialGradient(canvas.width/2, canvas.height/2, canvas.height/3, canvas.width/2, canvas.height/2, canvas.height);
  grad.addColorStop(0, 'rgba(0,0,0,0)');
  grad.addColorStop(1, 'rgba(0,0,0,0.3)');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, canvas.width, canvas.height);
}

// index.tsx: Связывает все вместе, управляет UI, сетевым взаимодействием и игровым циклом.
import { init as initGame, renderGame, getTile, destroyTile, canMoveTo, TILE_SIZE } from './game';
import { initInput } from './input';
import { Players, RoomInfo, Movement, Player, TileType } from './types';

// Поскольку socket.io загружается из CDN, мы объявляем глобальную переменную `io`
// и минимальный интерфейс Socket, чтобы TypeScript знал о них.
interface Socket {
  id: string;
  on(event: string, callback: (...args: any[]) => void): this;
  emit(event: string, ...args: any[]): this;
}
declare const io: (url: string) => Socket;

document.addEventListener('DOMContentLoaded', () => {
    // UI элементы
    const lobby = document.getElementById('lobby') as HTMLDivElement;
    const gameContainer = document.getElementById('game-container') as HTMLDivElement;
    const canvas = document.getElementById('game-canvas') as HTMLCanvasElement;

    // Элементы лобби
    const onlineCountSpan = document.getElementById('online-count') as HTMLSpanElement;
    const nicknameInput = document.getElementById('nickname-input') as HTMLInputElement;
    const roomNameInput = document.getElementById('room-name-input') as HTMLInputElement;
    const createRoomButton = document.getElementById('create-room-button') as HTMLButtonElement;
    const offlineButton = document.getElementById('offline-button') as HTMLButtonElement;
    const roomListContainer = document.getElementById('room-list-container') as HTMLDivElement;
    const noRoomsMessage = document.getElementById('no-rooms-message') as HTMLParagraphElement;

    // UI в игре
    const inventoryUI = document.getElementById('inventory-ui') as HTMLDivElement;
    const stoneCountSpan = document.getElementById('stone-count') as HTMLSpanElement;
    const woodCountSpan = document.getElementById('wood-count') as HTMLSpanElement;

    // Состояние клиента
    let players: Players = {};
    let localInventory = { stone: 0, wood: 0 };
    let isOffline = false;
    let localPlayerId = 'offline-player';

    // Подключение к серверу (может не использоваться в оффлайн режиме)
    let socket: Socket | null = null;

    const movement: Movement = initInput(canvas, handleMouseClick);

    // --- ФУНКЦИИ РАЗМЕРА ЭКРАНА ---

    function resizeCanvas() {
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;
    }

    // Слушаем изменение размера окна
    window.addEventListener('resize', resizeCanvas);


    // --- ОБРАБОТЧИКИ UI ЛОББИ ---

    function updateLobbyButtons() {
        const hasNickname = nicknameInput.value.trim().length > 0;
        createRoomButton.disabled = !hasNickname;
        offlineButton.disabled = !hasNickname;
        document.querySelectorAll<HTMLButtonElement>('.join-room-button').forEach(btn => {
            btn.disabled = !hasNickname;
        });
    }

    nicknameInput.addEventListener('input', updateLobbyButtons);

    createRoomButton.addEventListener('click', () => {
        if (!socket) connectToServer();
        const roomName = roomNameInput.value.trim();
        const nickname = nicknameInput.value.trim();
        socket?.emit('createRoom', roomName, nickname);
    });

    offlineButton.addEventListener('click', () => {
        isOffline = true;
        startGameOffline();
    });

    // --- УПРАВЛЕНИЕ ИГРОЙ ---

    function startGame(initialPlayers: Players, playerId: string) {
        lobby.classList.add('hidden');
        gameContainer.classList.remove('hidden');
        inventoryUI.classList.remove('hidden');

        // Устанавливаем размер canvas на весь экран при старте
        resizeCanvas();

        players = initialPlayers;
        if(players[playerId].inventory) {
            localInventory = players[playerId].inventory;
        }

        initGame(canvas, players[playerId]);
        gameLoop();
    }

    function startGameOffline() {
        const nickname = nicknameInput.value.trim() || "Player";
        const player: Player = {
            id: localPlayerId,
            x: 400,
            y: 300,
            color: `hsl(${Math.random() * 360}, 70%, 50%)`,
            nickname: nickname,
            inventory: { stone: 0, wood: 0 }
        };
        startGame({ [localPlayerId]: player }, localPlayerId);
    }

    // --- СЕТЕВОЕ ВЗАИМОДЕЙСТВИЕ ---

    function connectToServer() {
        if (socket) return;
        socket = io("https://rgp-game.onrender.com");

        socket.on('connect', () => {
            console.log('Connected to server with ID:', socket.id);
            localPlayerId = socket.id;
            updateLobbyButtons();
        });

        socket.on('onlineCount', (count: number) => {
            onlineCountSpan.textContent = String(count);
        });

        socket.on('roomList', (rooms: RoomInfo[]) => {
            roomListContainer.innerHTML = '';
            if (rooms.length === 0) {
                roomListContainer.appendChild(noRoomsMessage);
                noRoomsMessage.classList.remove('hidden');
            } else {
                if (noRoomsMessage) noRoomsMessage.classList.add('hidden');
                rooms.forEach(room => {
                    const roomElement = document.createElement('div');
                    roomElement.className = 'flex justify-between items-center p-3 bg-gray-800 rounded-md mb-2';
                    roomElement.innerHTML = `
                        <div>
                            <span class="font-semibold">${room.name}</span>
                            <span class="text-gray-400 ml-2">(${room.players}/10)</span>
                        </div>
                        <button data-room-id="${room.id}" class="join-room-button bg-green-600 hover:bg-green-700 text-white font-bold py-2 px-4 rounded transition duration-300 disabled:bg-gray-500 disabled:cursor-not-allowed">
                            Войти
                        </button>
                    `;
                    roomListContainer.appendChild(roomElement);
                });

                roomListContainer.addEventListener('click', (e) => {
                    const target = e.target as HTMLButtonElement;
                    if (target.matches('.join-room-button')) {
                        const roomId = target.getAttribute('data-room-id');
                        const nickname = nicknameInput.value.trim();
                        if (roomId) {
                            socket?.emit('joinRoom', roomId, nickname);
                        }
                    }
                });
            }
            updateLobbyButtons();
        });

        socket.on('gameStart', (initialPlayers: Players) => {
            isOffline = false;
            startGame(initialPlayers, socket!.id);
        });

        socket.on('state', (serverPlayers: Players) => {
            players = serverPlayers;
        });

        socket.on('error', (message: string) => {
            alert(`Ошибка: ${message}`);
        });
    }

    // Инициализируем при загрузке страницы
    connectToServer();


    // --- ОБРАБОТКА ВВОДА ---

    function handleMouseClick(mouseX: number, mouseY: number) {
        const me = players[localPlayerId];
        if (!me) return;

        const cameraX = me.x - canvas.width / 2;
        const cameraY = me.y - canvas.height / 2;
        const worldX = mouseX + cameraX;
        const worldY = mouseY + cameraY;
        const clickedTileX = Math.floor(worldX / TILE_SIZE);
        const clickedTileY = Math.floor(worldY / TILE_SIZE);
        const playerTileX = Math.floor(me.x / TILE_SIZE);
        const playerTileY = Math.floor(me.y / TILE_SIZE);
        const distance = Math.sqrt(Math.pow(playerTileX - clickedTileX, 2) + Math.pow(playerTileY - clickedTileY, 2));

        if (distance > 1.5) return;

        const tileType = getTile(clickedTileX, clickedTileY);
        if (tileType === 'tree') {
            destroyTile(clickedTileX, clickedTileY);
            localInventory.wood++;
        } else if (tileType === 'stone') {
            destroyTile(clickedTileX, clickedTileY);
            localInventory.stone++;
        }
    }

    // --- ИГРОВОЙ ЦИКЛ ---

    function gameLoop() {
        if (gameContainer.classList.contains('hidden')) return;

        const me = players[localPlayerId];
        if (me) {
            const SPEED = 5;
            const PLAYER_RADIUS = 20;

            if (isOffline) {
                // В оффлайн режиме двигаем игрока локально
                let dx = 0;
                let dy = 0;
                if (movement.up) dy -= SPEED;
                if (movement.down) dy += SPEED;
                if (movement.left) dx -= SPEED;
                if (movement.right) dx += SPEED;

                if (canMoveTo(me.x + dx, me.y + dy, PLAYER_RADIUS * 2, PLAYER_RADIUS * 2)) {
                    me.x += dx;
                    me.y += dy;
                }
            } else {
                 // В онлайн режиме отправляем ввод на сервер
                const filteredMovement = { ...movement };
                if (filteredMovement.up && !canMoveTo(me.x, me.y - SPEED, PLAYER_RADIUS * 2, PLAYER_RADIUS * 2)) filteredMovement.up = false;
                if (filteredMovement.down && !canMoveTo(me.x, me.y + SPEED, PLAYER_RADIUS * 2, PLAYER_RADIUS * 2)) filteredMovement.down = false;
                if (filteredMovement.left && !canMoveTo(me.x - SPEED, me.y, PLAYER_RADIUS * 2, PLAYER_RADIUS * 2)) filteredMovement.left = false;
                if (filteredMovement.right && !canMoveTo(me.x + SPEED, me.y, PLAYER_RADIUS * 2, PLAYER_RADIUS * 2)) filteredMovement.right = false;
                socket?.emit('movement', filteredMovement);
            }
        }

        // Обновляем UI
        stoneCountSpan.textContent = String(localInventory.stone);
        woodCountSpan.textContent = String(localInventory.wood);

        renderGame(players, localPlayerId);
        requestAnimationFrame(gameLoop);
    }
});

// input.ts: Управляет обработкой ввода от пользователя.
import { Movement } from './types';

/**
 * Инициализирует обработчики событий клавиатуры и мыши.
 * @param canvas - Элемент HTMLCanvasElement для отслеживания кликов.
 * @param onMouseClick - Callback-функция, вызываемая при клике.
 * @returns {Movement} - Объект состояния движения.
 */
export function initInput(canvas: HTMLCanvasElement, onMouseClick: (x: number, y: number) => void): Movement {
    const movement: Movement = { up: false, down: false, left: false, right: false };

    window.addEventListener('keydown', (e: KeyboardEvent) => {
        // Приводим к нижнему регистру для надежности
        const key = e.key.toLowerCase();

        switch (key) {
            case 'w': case 'arrowup': case 'ц': movement.up = true; break;
            case 'a': case 'arrowleft': case 'ф': movement.left = true; break;
            case 's': case 'arrowdown': case 'ы': movement.down = true; break;
            case 'd': case 'arrowright': case 'в': movement.right = true; break;
        }
    });

    window.addEventListener('keyup', (e: KeyboardEvent) => {
         const key = e.key.toLowerCase();

         switch (key) {
            case 'w': case 'arrowup': case 'ц': movement.up = false; break;
            case 'a': case 'arrowleft': case 'ф': movement.left = false; break;
            case 's': case 'arrowdown': case 'ы': movement.down = false; break;
            case 'd': case 'arrowright': case 'в': movement.right = false; break;
        }
    });

    canvas.addEventListener('click', (e: MouseEvent) => {
        const rect = canvas.getBoundingClientRect();
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;
        onMouseClick(mouseX, mouseY);
    });

    return movement;
}

